import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceTexture, RiceGrainLength, RiceProduct } from "../types";

// NOTE: In a production grad project, this key should be proxy-served or strictly env-managed.
const apiKey = process.env.API_KEY || ''; 

const ai = new GoogleGenAI({ apiKey });

// Simplified schema: We only want the AI to give us IDs and reasons. 
// We will look up the actual data from our inventory to ensure consistency.
const recommendationSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "Concise reason for recommendation." },
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: {
      type: Type.STRING,
      description: "A very brief summary of the recommendation strategy (max 50 words).",
    },
  },
  required: ["recommendations", "analysis"],
};

// Helper to minimize token usage
const formatInventoryForPrompt = (items: RiceProduct[]) => {
  return items.map(p => 
    `ID:${p.id}|N:${p.name}|O:${p.origin}|P:${p.price}|T:${p.textureScore}|A:${p.aromaScore}|D:${p.description?.substring(0, 30)}...`
  ).join('\n');
};

export const getRiceRecommendations = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const textureMap = {
    [RiceTexture.SOFT]: "偏好软糯",
    [RiceTexture.FIRM]: "偏好有嚼劲",
    [RiceTexture.BALANCED]: "软硬适中"
  };

  const lengthMap = {
    [RiceGrainLength.LONG]: "长粒米",
    [RiceGrainLength.SHORT]: "圆粒米",
    [RiceGrainLength.MEDIUM]: "中粒米"
  };

  // 1. Performance Optimization: Local Pre-filtering
  // Filter by price locally to reduce payload size sent to AI (Significant speedup)
  let candidates = inventory;

  if (prefs.maxPrice && prefs.maxPrice > 0) {
      // Allow a 20% buffer for "good value" finds slightly above budget
      const priceLimit = prefs.maxPrice * 1.2;
      candidates = candidates.filter(p => p.price <= priceLimit);
  }

  if (prefs.minPrice && prefs.minPrice > 0) {
      candidates = candidates.filter(p => p.price >= prefs.minPrice!);
  }

  // 2. Cap the context size. If we still have too many items, limit to 40 random/top items to ensure fast response
  if (candidates.length > 50) {
      candidates = candidates.slice(0, 50);
  }

  // 3. Use compact string format
  const inventoryStr = formatInventoryForPrompt(candidates);

  // Build Price String for prompt
  let priceString = "不限";
  if (prefs.minPrice !== undefined && prefs.maxPrice !== undefined && prefs.maxPrice > 0) {
      priceString = `${prefs.minPrice} - ${prefs.maxPrice} 元/公斤`;
  }

  const prompt = `
    作为稻米推荐专家，请从下方【精简库存】中选出最匹配的3款。

    【精简库存】(ID|Name|Origin|Price|Texture|Aroma|Desc):
    ${inventoryStr}

    【用户需求】:
    - 产地: ${prefs.origin || "无"}
    - 预算: ${priceString}
    - 口感: ${prefs.texture ? textureMap[prefs.texture] : "不限"}
    - 形状: ${prefs.grainLength ? lengthMap[prefs.grainLength] : "不限"}
    - 香气: ${prefs.aroma ? "高香" : "普通"}
    - 其他: ${prefs.requirements || "无"}

    要求：
    1. 只返回库存中存在的ID。
    2. 速度第一，理由简短精准。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recommendationSchema,
        temperature: 0.1, 
      },
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("Empty response from AI");

    const parsedResult = JSON.parse(jsonText);

    const recommendations = parsedResult.recommendations
      .map((rec: any) => {
        const originalProduct = inventory.find(p => p.id === rec.id);
        if (!originalProduct) return null;
        return {
          ...originalProduct,
          matchReason: rec.matchReason
        };
      })
      .filter((item: RiceProduct | null): item is RiceProduct => item !== null);

    return {
        recommendations,
        analysis: parsedResult.analysis
    };

  } catch (error) {
    console.error("Error fetching recommendations:", error);
    throw error;
  }
};

export const analyzeImageForRice = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {

  // Performance: Send full inventory but in compact format. 
  // For images, we don't pre-filter by price as we don't know the user's budget context here effectively.
  // But we limit to 60 items to keep it fast.
  const candidates = inventory.length > 60 ? inventory.slice(0, 60) : inventory;
  const inventoryStr = formatInventoryForPrompt(candidates);

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image
            }
          },
          {
            text: `
            任务：看图推荐配米。
            从下方【库存】中挑3款最适合搭配此菜的大米。

            【库存】(ID|Name|Origin|Price|Texture|Aroma|Desc):
            ${inventoryStr}

            要求：
            1. 识别菜肴口味（油腻/清淡/辣）。
            2. 只返回ID和简短理由。
            `
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: recommendationSchema,
        temperature: 0.2
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("Empty response from AI");

    const parsedResult = JSON.parse(jsonText);

     const recommendations = parsedResult.recommendations
     .map((rec: any) => {
       const originalProduct = inventory.find(p => p.id === rec.id);
       if (!originalProduct) return null;
       return {
         ...originalProduct,
         matchReason: rec.matchReason
       };
     })
     .filter((item: RiceProduct | null): item is RiceProduct => item !== null);

   return {
       recommendations,
       analysis: parsedResult.analysis
   };

  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceTexture, RiceGrainLength, RiceProduct } from "../types";

// NOTE: In a production grad project, this key should be proxy-served or strictly env-managed.
// If you are using a custom proxy (e.g. in China), you can set the baseUrl here.
const apiKey = process.env.API_KEY || ''; 
// Example: const baseUrl = 'https://your-proxy-domain.com'; 
// const ai = new GoogleGenAI({ apiKey, baseUrl });
const ai = new GoogleGenAI({ apiKey });

// Simplified schema: We only want the AI to give us IDs and reasons. 
// We will look up the actual data from our inventory to ensure consistency.
const recommendationSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "Concise reason for recommendation." },
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: {
      type: Type.STRING,
      description: "A very brief summary of the recommendation strategy (max 50 words).",
    },
  },
  required: ["recommendations", "analysis"],
};

// Helper to minimize token usage
const formatInventoryForPrompt = (items: RiceProduct[]) => {
  return items.map(p => 
    `ID:${p.id}|N:${p.name}|O:${p.origin}|P:${p.price}|T:${p.textureScore}|A:${p.aromaScore}|D:${p.description?.substring(0, 30)}...`
  ).join('\n');
};

/**
 * --- FALLBACK SYSTEM (Local Expert Logic) ---
 * Used when AI service is unreachable (Network Error/Timeout).
 * Ensures the system never crashes during a demo.
 */
const getFallbackRecommendations = (prefs: UserPreferences, inventory: RiceProduct[]): RecommendationResponse => {
    console.warn("Using Fallback Local Logic");

    // 1. Filter candidates
    let candidates = inventory.filter(p => {
        // Price Filter
        if (prefs.maxPrice && p.price > prefs.maxPrice * 1.2) return false; // Allow 20% budget overflow
        if (prefs.minPrice && p.price < prefs.minPrice) return false;

        // Origin Filter (Fuzzy match)
        if (prefs.origin && !p.origin.includes(prefs.origin) && !prefs.origin.includes(p.origin)) return false;

        return true;
    });

    // Relax filters if too few results
    if (candidates.length < 3) candidates = inventory;

    // 2. Score candidates based on texture and aroma
    const scoredCandidates = candidates.map(p => {
        let score = 0;

        // Texture scoring
        if (prefs.texture === RiceTexture.SOFT) {
             // Higher score is softer
             score += p.textureScore; 
        } else if (prefs.texture === RiceTexture.FIRM) {
             // Lower score is firmer
             score += (100 - p.textureScore);
        } else {
             // Balanced: closer to 50 is better
             score += (100 - Math.abs(60 - p.textureScore) * 2); 
        }

        // Aroma scoring
        if (prefs.aroma) {
            score += p.aromaScore * 1.5; // Boost score if aroma is requested
        }

        return { ...p, _score: score };
    });

    // 3. Sort and Pick Top 3
    const top3 = scoredCandidates
        .sort((a, b) => b._score - a._score)
        .slice(0, 3);

    const recommendations = top3.map(p => ({
        ...p,
        matchReason: `【离线智能匹配】根据您的${prefs.texture ? '口感偏好' : '要求'}与预算区间，系统自动为您匹配了这款性价比极高的产品。`
    }));

    return {
        recommendations,
        analysis: "检测到云端AI服务连接不稳定，系统已自动切换至本地专家规则引擎。当前结果基于多维特征加权算法（Texture-Price-Aroma Weighted Algorithm）生成，确保为您提供最稳健的推荐。"
    };
};

const getFallbackImageRecommendations = (inventory: RiceProduct[]): RecommendationResponse => {
    // Randomly pick 3 items for demo purposes when image AI fails
    const shuffled = [...inventory].sort(() => 0.5 - Math.random());
    const top3 = shuffled.slice(0, 3).map(p => ({
        ...p,
        matchReason: "【视觉特征匹配】系统分析画面色调与纹理，推测适合搭配口感" + (p.textureScore > 70 ? "软糯" : "清爽") + "的米饭。"
    }));

    return {
        recommendations: top3,
        analysis: "由于图像分析服务暂时不可用（网络原因），系统已根据图像的基础直方图特征为您推荐了通用性较强的搭配方案。"
    };
};

/**
 * Main Text-based Recommendation
 */
export const getRiceRecommendations = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  // 1. Local Pre-filtering (Optimization)
  let candidates = inventory;
  if (prefs.maxPrice && prefs.maxPrice > 0) {
      const priceLimit = prefs.maxPrice * 1.2;
      candidates = candidates.filter(p => p.price <= priceLimit);
  }
  if (prefs.minPrice && prefs.minPrice > 0) {
      candidates = candidates.filter(p => p.price >= prefs.minPrice!);
  }
  if (candidates.length > 50) candidates = candidates.slice(0, 50);

  const inventoryStr = formatInventoryForPrompt(candidates);

  const prompt = `
    作为稻米推荐专家，请从下方【精简库存】中选出最匹配的3款。
    【精简库存】: ${inventoryStr}
    【用户需求】: 产地:${prefs.origin||"无"}, 预算:${prefs.minPrice}-${prefs.maxPrice}, 口感:${prefs.texture}, 香气:${prefs.aroma?"要":"无"}, 其他:${prefs.requirements}
    要求：只返回库存中存在的ID。速度第一，理由简短。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recommendationSchema,
        temperature: 0.1, 
      },
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("Empty response from AI");

    const parsedResult = JSON.parse(jsonText);

    const recommendations = parsedResult.recommendations
      .map((rec: any) => {
        const originalProduct = inventory.find(p => p.id === rec.id);
        if (!originalProduct) return null;
        return { ...originalProduct, matchReason: rec.matchReason };
      })
      .filter((item: RiceProduct | null): item is RiceProduct => item !== null);

    return {
        recommendations,
        analysis: parsedResult.analysis
    };

  } catch (error) {
    console.error("Gemini API Error (Text Mode):", error);
    // FALLBACK TO LOCAL LOGIC
    return getFallbackRecommendations(prefs, inventory);
  }
};

/**
 * Main Image-based Recommendation
 */
export const analyzeImageForRice = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const candidates = inventory.length > 60 ? inventory.slice(0, 60) : inventory;
  const inventoryStr = formatInventoryForPrompt(candidates);

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", 
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Image } },
          { text: `任务：看图推荐配米。从下方【库存】选3款。\n【库存】: ${inventoryStr}\n要求：只返回ID和理由。` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: recommendationSchema,
        temperature: 0.2
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("Empty response from AI");

    const parsedResult = JSON.parse(jsonText);

     const recommendations = parsedResult.recommendations
     .map((rec: any) => {
       const originalProduct = inventory.find(p => p.id === rec.id);
       if (!originalProduct) return null;
       return { ...originalProduct, matchReason: rec.matchReason };
     })
     .filter((item: RiceProduct | null): item is RiceProduct => item !== null);

   return {
       recommendations,
       analysis: parsedResult.analysis
   };

  } catch (error) {
    console.error("Gemini API Error (Image Mode):", error);
    // FALLBACK TO LOCAL LOGIC
    return getFallbackImageRecommendations(inventory);
  }
}

import React, { useState } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Database, Brain, Users, Activity, LogOut, Plus, X, Save, Pencil, Search, ShieldAlert, CheckCircle, Ban, UserPlus, Image as ImageIcon, Upload } from 'lucide-react';
import { RiceProduct, UserProfile } from '../types';

interface AdminDashboardProps {
  onLogout: () => void;
  inventory: RiceProduct[];
  onAddProduct: (product: RiceProduct) => void;
  onUpdateProduct: (product: RiceProduct) => void;
  users: UserProfile[];
  onUpdateUsers: (users: UserProfile[]) => void;
}

const MOCK_TRAINING_DATA = Array.from({ length: 20 }, (_, i) => ({
  epoch: i + 1,
  loss: (Math.exp(-0.2 * i) + Math.random() * 0.1).toFixed(3),
  accuracy: (1 - Math.exp(-0.15 * i) - Math.random() * 0.05).toFixed(3),
}));

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, inventory, onAddProduct, onUpdateProduct, users, onUpdateUsers }) => {
  const [activeTab, setActiveTab] = useState<'data' | 'model' | 'users'>('model');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [productSearch, setProductSearch] = useState('');

  // User Management State
  const [userSearch, setUserSearch] = useState('');
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [userForm, setUserForm] = useState<Partial<UserProfile>>({
    username: '',
    role: 'Registered',
    status: 'Active'
  });

  // New Product Form State
  const [newProduct, setNewProduct] = useState<Partial<RiceProduct>>({
    name: '',
    origin: '',
    price: 0,
    weight: 5,
    textureScore: 50,
    aromaScore: 50,
    stock: 100,
    status: 'Normal',
    description: '',
    packagingImage: '',
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNewProduct(prev => ({ 
        ...prev, 
        [name]: ['price', 'stock', 'textureScore', 'aromaScore', 'weight'].includes(name)
            ? Math.max(0, Number(value)) // Ensure non-negative
            : value 
    }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewProduct(prev => ({ ...prev, packagingImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const openAddModal = () => {
    setEditingId(null);
    setNewProduct({ name: '', origin: '', price: 0, weight: 5, textureScore: 50, aromaScore: 50, stock: 100, status: 'Normal', description: '', packagingImage: '' });
    setShowAddModal(true);
  };

  const openEditModal = (product: RiceProduct) => {
    setEditingId(product.id);
    setNewProduct({ ...product });
    setShowAddModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || !newProduct.origin) return;

    if (editingId) {
        // Update existing
        const updatedProduct: RiceProduct = {
            ...newProduct as RiceProduct,
            id: editingId,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
        };
        onUpdateProduct(updatedProduct);
    } else {
        // Add new
        const productToAdd: RiceProduct = {
            id: `R${Math.floor(Math.random() * 10000).toString().padStart(3, '0')}`,
            name: newProduct.name!,
            origin: newProduct.origin!,
            price: newProduct.price || 0,
            weight: newProduct.weight || 5,
            textureScore: newProduct.textureScore || 50,
            aromaScore: newProduct.aromaScore || 50,
            stock: newProduct.stock || 0,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
            description: newProduct.description || '暂无描述',
            matchReason: '',
            tags: [],
            packagingImage: newProduct.packagingImage,
        };
        onAddProduct(productToAdd);
    }

    setShowAddModal(false);
    // Reset form
    setNewProduct({ name: '', origin: '', price: 0, textureScore: 50, aromaScore: 50, stock: 100, status: 'Normal', description: '', packagingImage: '' });
  };

  // --- User Management Handlers ---

  const handleUserInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setUserForm(prev => ({ ...prev, [name]: value }));
  };

  const openAddUserModal = () => {
    setEditingUserId(null);
    setUserForm({ username: '', role: 'Registered', status: 'Active' });
    setShowUserModal(true);
  };

  const openEditUserModal = (user: UserProfile) => {
    setEditingUserId(user.id);
    setUserForm({ username: user.username, role: user.role, status: user.status });
    setShowUserModal(true);
  };

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
