const INITIAL_USERS: UserProfile[] = [
    { id: 'U1023', username: 'RiceLover_01', ip: '192.168.1.101', role: 'Registered', status: 'Active', lastActive: '2 mins ago', requestCount: 45, favorites: ['R001'] },
    { id: 'U1024', username: 'Guest_882', ip: '192.168.1.105', role: 'Guest', status: 'Active', lastActive: '5 mins ago', requestCount: 12, favorites: [] },
    { id: 'U1025', username: 'SushiMaster', ip: '192.168.1.112', role: 'Registered', status: 'Banned', lastActive: '3 days ago', requestCount: 120, favorites: [] },
    { id: 'U1026', username: 'Guest_991', ip: '192.168.1.101', role: 'Guest', status: 'Active', lastActive: '15 mins ago', requestCount: 3, favorites: [] },
    { id: 'U1027', username: 'Farmer_Li', ip: '10.0.0.5', role: 'Registered', status: 'Active', lastActive: '1 hour ago', requestCount: 89, favorites: [] },
];

const App: React.FC = () => {
  // Auth State
  const [userRole, setUserRole] = useState<UserRole>(null);

  // Real User Database (Persisted)
  const [users, setUsers] = useState<UserProfile[]>(() => {
    const saved = localStorage.getItem('rice_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  // Logged In Client User
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);

  // Data State (Single Source of Truth)
  const [inventory, setInventory] = useState<RiceProduct[]>(INITIAL_INVENTORY);

  // User Client State
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RecommendationResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [viewMode, setViewMode] = useState<'search' | 'favorites'>('search');

  // Persist Users
  useEffect(() => {
    localStorage.setItem('rice_users', JSON.stringify(users));
  }, [users]);

  // Sync Current User with Users DB
  useEffect(() => {
    if (currentUser) {
      const updatedUser = users.find(u => u.id === currentUser.id);
      if (updatedUser) {
        // Only update if there are meaningful changes to avoid loops, 
        // though setUsers ensures reference stability mostly.
        // For simplicity, we trust the DB source of truth.
        if (JSON.stringify(updatedUser) !== JSON.stringify(currentUser)) {
             setCurrentUser(updatedUser);
        }
      }
    }
  }, [users, currentUser]);

  const handleLoginPortal = (role: UserRole) => {
    setUserRole(role);
    setResults(null); // Reset client state on login
    setViewMode('search');
    // If admin login, clear current user
    if (role === 'admin') setCurrentUser(null);
  };

  const handleLogout = () => {
    setUserRole(null);
    setResults(null);
    setCurrentUser(null);
    setViewMode('search');
  };

  const handleAddProduct = (newProduct: RiceProduct) => {
    setInventory(prev => [...prev, newProduct]);
  };

  const handleUpdateProduct = (updatedProduct: RiceProduct) => {
    setInventory(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => {
      setUsers(updatedUsers);
  };

  // --- Client Side Auth Logic ---
  const handleClientRegister = (username: string, password?: string) => {
    if (users.some(u => u.username === username)) {
      throw new Error("用户名已存在");
    }
    const newUser: UserProfile = {
      id: `U${Date.now()}`,
      username,
      password, // In real app, hash this
      role: 'Registered',
      status: 'Active',
      ip: '127.0.0.1', // Mock IP
      lastActive: 'Just now',
      requestCount: 0,
      favorites: []
    };
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  };

  const handleClientLogin = (username: string, password?: string) => {
    const user = users.find(u => u.username === username && u.password === password && u.status === 'Active');
    if (!user) {
      throw new Error("用户名或密码错误，或账号已被封禁");
    }
    setCurrentUser(user);
  };

  const toggleFavorite = (productId: string) => {
    if (!currentUser) {
      setShowAuthModal(true);
      return;
    }

    setUsers(prevUsers => prevUsers.map(u => {
      if (u.id === currentUser.id) {
        const isFav = u.favorites.includes(productId);
        const newFavs = isFav 
          ? u.favorites.filter(id => id !== productId)
          : [...u.favorites, productId];
        return { ...u, favorites: newFavs };
      }
      return u;
    }));
  };

  // --- User Client Logic ---
  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    setViewMode('search');
    try {
      const data = await getRiceRecommendations(prefs, inventory);
      setResults(data);
    } catch (err) {
      console.error(err);
      setError("系统繁忙，请稍后再试或检查您的网络连接。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    setViewMode('search');
    try {
      const data = await analyzeImageForRice(base64, inventory);
      setResults(data);
    } catch (err) {
       console.error(err);
      setError("图片分析失败，请重试。");
    } finally {
      setIsLoading(false);
    }
  }

  const reset = () => {
    setResults(null);
    setViewMode('search');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // --- View Computations ---
  const favoriteProducts = currentUser 
    ? inventory.filter(p => currentUser.favorites.includes(p.id))
    : [];

  // --- Render Logic ---

  if (!userRole) {
    return <Login onLogin={handleLoginPortal} />;
  }

  if (userRole === 'admin') {
    return (
      <AdminDashboard 
        onLogout={handleLogout} 
        inventory={inventory}
        onAddProduct={handleAddProduct}
        onUpdateProduct={handleUpdateProduct}
        users={users}
        onUpdateUsers={handleUpdateUsers}
      />
    );
  }

  // User Role View (Consumer Client)
  return (
    <div className="min-h-screen bg-[#fafafa] text-gray-900 font-sans selection:bg-emerald-100 relative">

      {/* Top Header */}
      <div className="absolute top-0 left-0 w-full p-4 flex justify-between items-center z-20 pointer-events-none">
          {/* Top Left: Auth / User Info */}
          <div className="pointer-events-auto">
             {!currentUser ? (
               <button 
                 onClick={() => setShowAuthModal(true)}
                 className="flex items-center gap-2 bg-white/80 backdrop-blur shadow-sm border border-gray-200 px-4 py-2 rounded-full text-sm font-medium text-gray-700 hover:text-emerald-600 hover:border-emerald-200 transition-all"
               >
                 <LogIn className="w-4 h-4" />
                 登录 / 注册
               </button>
             ) : (
                <div className="flex items-center gap-3">
                   <div className="flex items-center gap-2 bg-white/80 backdrop-blur shadow-sm border border-gray-200 px-4 py-2 rounded-full text-sm font-medium text-gray-700">
                      <div className="w-5 h-5 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-xs font-bold">
                        {currentUser.username.charAt(0).toUpperCase()}
                      </div>
                      Hi, {currentUser.username}
                   </div>

                   <button 
                      onClick={() => setViewMode(viewMode === 'search' ? 'favorites' : 'search')}
                      className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all shadow-sm border ${viewMode === 'favorites' ? 'bg-red-50 text-red-600 border-red-200' : 'bg-white/80 text-gray-600 border-gray-200 hover:text-red-500'}`}
                   >
                      <Heart className={`w-4 h-4 ${viewMode === 'favorites' ? 'fill-current' : ''}`} />
                      我的收藏 ({currentUser.favorites.length})
                   </button>
                </div>
             )}
          </div>

          {/* Top Right: Logout */}
          <div className="pointer-events-auto">
            <button 
              onClick={handleLogout}
              className="text-xs text-gray-400 hover:text-gray-600 flex items-center gap-1 transition-colors px-3 py-2 rounded-lg hover:bg-gray-100 bg-white/50 backdrop-blur"
            >
              <LogOut className="w-3 h-3" />
              退出
            </button>
          </div>
      </div>

      <div className="w-full max-w-[1600px] mx-auto px-4 md:px-8 py-20 md:py-24">

        {/* Favorites View */}
        {viewMode === 'favorites' && currentUser ? (
           <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-6">
                 <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                    <Heart className="w-6 h-6 text-red-500 fill-red-500" />
                    我的收藏
                 </h2>
                 <button onClick={() => setViewMode('search')} className="text-sm text-emerald-600 hover:underline">
                    返回搜索
                 </button>
              </div>
              <ResultsGrid 
                  products={favoriteProducts} 
                  analysisText="" 
                  favorites={currentUser.favorites} 
                  onToggleFavorite={toggleFavorite}
                  showAnalysis={false}
              />
           </div>
        ) : (
          /* Search/Recommend View */
          <>
            <div className={`transition-all duration-500 ${results ? 'mb-8' : 'flex flex-col items-center justify-center min-h-[60vh]'}`}>
                <div className="w-full max-w-3xl mx-auto">
                    <Hero />
                    {!results && (
                        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 w-full">
                            <PreferenceForm 
                                onSubmitPreferences={handlePreferenceSubmit} 
                                onSubmitImage={handleImageSubmit}
                                isLoading={isLoading} 
                            />
                            {error && (
                                <div className="mt-6 p-4 bg-red-50 text-red-600 text-sm rounded-xl text-center">
                                    {error}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {results && (
                <div className="w-full animate-in fade-in slide-in-from-bottom-8 duration-700 space-y-6">
                    <div className="flex justify-between items-center px-2">
                        <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                           <Search className="w-5 h-5" /> 推荐分析结果
                        </h2>
                        <button 
                            onClick={reset}
                            className="flex items-center gap-2 text-sm text-gray-500 hover:text-emerald-600 transition-colors px-3 py-1.5 rounded-lg hover:bg-emerald-50"
                        >
                            <RotateCcw className="w-4 h-4" />
                            重新筛选
                        </button>
                    </div>

                    <AnalysisChart products={results.recommendations} />
                    <ResultsGrid 
                        products={results.recommendations} 
                        analysisText={results.analysis} 
                        favorites={currentUser?.favorites || []}
                        onToggleFavorite={toggleFavorite}
                    />

                    <div className="text-center pt-10">
                        <p className="text-xs text-gray-400">© 2024 RiceRec Project. Demo Version.</p>
                    </div>
                </div>
            )}
          </>
        )}
      </div>

      {/* Auth Modal */}
      {showAuthModal && (
        <UserAuthModal 
           onClose={() => setShowAuthModal(false)}
           onLogin={handleClientLogin}
           onRegister={handleClientRegister}
        />
      )}
    </div>
  );
};

export default App;

