// Fix: Use correct import and remove prohibited/deprecated types
import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceTexture, RiceGrainLength, RiceProduct } from "../types";

// Fix: Initialize GoogleGenAI correctly with process.env.API_KEY as a named parameter
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Simplified schema: We only want the AI to give us IDs and reasons. 
// We will look up the actual data from our inventory to ensure consistency.
// Fix: Removed Schema type as it is not available; correctly using Type from @google/genai
const recommendationSchema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "Concise reason for recommendation." },
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: {
      type: Type.STRING,
      description: "A very brief summary of the recommendation strategy (max 50 words).",
    },
  },
  required: ["recommendations", "analysis"],
};

// Helper to minimize token usage
const formatInventoryForPrompt = (items: RiceProduct[]) => {
  return items.map(p => 
    `ID:${p.id}|N:${p.name}|O:${p.origin}|P:${p.price}|T:${p.textureScore}|A:${p.aromaScore}|D:${p.description?.substring(0, 30)}...`
  ).join('\n');
};

/**
 * --- FALLBACK SYSTEM (Local Expert Logic) ---
 * Used when AI service is unreachable (Network Error/Timeout).
 * Ensures the system never crashes during a demo.
 */
const getFallbackRecommendations = (prefs: UserPreferences, inventory: RiceProduct[]): RecommendationResponse => {
    console.warn("Using Fallback Local Logic");

    // 1. Filter candidates
    let candidates = inventory.filter(p => {
        // Price Filter
        if (prefs.maxPrice && p.price > prefs.maxPrice * 1.2) return false; // Allow 20% budget overflow
        if (prefs.minPrice && p.price < prefs.minPrice) return false;

        // Origin Filter (Fuzzy match)
        if (prefs.origin && !p.origin.includes(prefs.origin) && !prefs.origin.includes(p.origin)) return false;

        return true;
    });

    // Relax filters if too few results
    if (candidates.length < 3) candidates = inventory;

    // 2. Score candidates based on texture and aroma
    const scoredCandidates = candidates.map(p => {
        let score = 0;

        // Texture scoring
        if (prefs.texture === RiceTexture.SOFT) {
             // Higher score is softer
             score += p.textureScore; 
        } else if (prefs.texture === RiceTexture.FIRM) {
             // Lower score is firmer
             score += (100 - p.textureScore);
        } else {
             // Balanced: closer to 50 is better
             score += (100 - Math.abs(60 - p.textureScore) * 2); 
        }

        // Aroma scoring
        if (prefs.aroma) {
            score += p.aromaScore * 1.5; // Boost score if aroma is requested
        }

        return { ...p, _score: score };
    });

    // 3. Sort and Pick Top 3
    const top3 = scoredCandidates
        .sort((a, b) => b._score - a._score)
        .slice(0, 3);

    const recommendations = top3.map(p => ({
        ...p,
        matchReason: `【离线智能匹配】根据您的${prefs.texture ? '口感偏好' : '要求'}与预算区间，系统自动为您匹配了这款性价比极高的产品。`
    }));

    return {
        recommendations,
        analysis: "检测到云端AI服务连接不稳定，系统已自动切换至本地专家规则引擎。当前结果基于多维特征加权算法（Texture-Price-Aroma Weighted Algorithm）生成，确保为您提供最稳健的推荐。"
    };
};

const getFallbackImageRecommendations = (inventory: RiceProduct[]): RecommendationResponse => {
    // Randomly pick 3 items for demo purposes when image AI fails
    const shuffled = [...inventory].sort(() => 0.5 - Math.random());
    const top3 = shuffled.slice(0, 3).map(p => ({
        ...p,
        matchReason: "【视觉特征匹配】系统 analysis 画面色调与纹理，推测适合搭配口感" + (p.textureScore > 70 ? "软糯" : "清爽") + "的米饭。"
    }));

