                              <input required type="text" name="name" value={newProduct.name} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" placeholder="例如：盘锦大米" />
                          </div>
                          <div>
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">产地</label>
                              <input required type="text" name="origin" value={newProduct.origin} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" placeholder="省份/城市" />
                          </div>
                          <div>
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">价格 (¥/kg)</label>
                              <input required type="number" min="0" step="0.1" name="price" value={newProduct.price} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" />
                          </div>
                           <div>
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">重量规格 (kg/袋)</label>
                              <input required type="number" min="0" step="0.5" name="weight" value={newProduct.weight} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" placeholder="5.0" />
                          </div>
                           <div>
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">软糯度 (0-100)</label>
                              <input type="number" name="textureScore" min="0" max="100" value={newProduct.textureScore} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" />
                          </div>
                           <div>
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">香气值 (0-100)</label>
                              <input type="number" name="aromaScore" min="0" max="100" value={newProduct.aromaScore} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" />
                          </div>
                          <div>
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">库存</label>
                              <input type="number" min="0" name="stock" value={newProduct.stock} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" />
                          </div>
                           <div className="col-span-2">
                              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">描述/备注</label>
                              <textarea name="description" value={newProduct.description} onChange={handleInputChange} rows={2} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" placeholder="简要描述产品特性..." />
                          </div>
                      </div>

                      <div className="pt-4 flex justify-end gap-3 pb-2">
                          <button type="button" onClick={() => setShowAddModal(false)} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">取消</button>
                          <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg transition-colors flex items-center gap-2">
                              <Save className="w-4 h-4" />
                              {editingId ? '保存更改' : '保存数据'}
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Add/Edit User Modal */}
      {showUserModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
              <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                  <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                      <h3 className="font-bold text-gray-900">
                        {editingUserId ? '编辑用户信息' : '新增用户'}
                      </h3>
                      <button onClick={() => setShowUserModal(false)} className="text-gray-400 hover:text-gray-600">
                          <X className="w-5 h-5" />
                      </button>
                  </div>

                  <form onSubmit={handleUserSubmit} className="p-6 space-y-4">
                      <div>
                          <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">用户昵称</label>
                          <input required type="text" name="username" value={userForm.username} onChange={handleUserInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500" placeholder="例如：User_123" />
                      </div>

                      <div>
                          <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">用户角色</label>
                          <select name="role" value={userForm.role} onChange={handleUserInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500">
                              <option value="Guest">Guest (访客)</option>
                              <option value="Registered">Registered (注册用户)</option>
                          </select>
                      </div>

                      <div>
                          <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">账户状态</label>
                          <select name="status" value={userForm.status} onChange={handleUserInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500">
                              <option value="Active">Active (正常)</option>
                              <option value="Banned">Banned (封禁)</option>
                          </select>
                      </div>

                      <div className="pt-4 flex justify-end gap-3 pb-2">
                          <button type="button" onClick={() => setShowUserModal(false)} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">取消</button>
                          <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg transition-colors flex items-center gap-2">
                              <Save className="w-4 h-4" />
                              {editingUserId ? '保存更改' : '创建用户'}
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { Database, Users, LogOut, Plus, X, Save, Pencil, Search, ShieldAlert, CheckCircle, Ban, UserPlus, Image as ImageIcon, Upload, Activity } from 'lucide-react';
import { RiceProduct, UserProfile } from '../types';

interface AdminDashboardProps {
  onLogout: () => void;
  inventory: RiceProduct[];
  onAddProduct: (product: RiceProduct) => void;
  onUpdateProduct: (product: RiceProduct) => void;
  users: UserProfile[];
  onUpdateUsers: (users: UserProfile[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, inventory, onAddProduct, onUpdateProduct, users, onUpdateUsers }) => {
  const [activeTab, setActiveTab] = useState<'data' | 'users'>('data');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [productSearch, setProductSearch] = useState('');

  // User Management State
  const [userSearch, setUserSearch] = useState('');
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [userForm, setUserForm] = useState<Partial<UserProfile>>({
    username: '',
    role: 'Registered',
    status: 'Active'
  });

  // New Product Form State
  const [newProduct, setNewProduct] = useState<Partial<RiceProduct>>({
    name: '',
    origin: '',
    price: 0,
    weight: 5,
    textureScore: 50,
    aromaScore: 50,
    stock: 100,
    status: 'Normal',
    description: '',
    packagingImage: '',
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNewProduct(prev => ({ 
        ...prev, 
        [name]: ['price', 'stock', 'textureScore', 'aromaScore', 'weight'].includes(name)
            ? Math.max(0, Number(value)) // Ensure non-negative
            : value 
    }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewProduct(prev => ({ ...prev, packagingImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const openAddModal = () => {
    setEditingId(null);
    setNewProduct({ name: '', origin: '', price: 0, weight: 5, textureScore: 50, aromaScore: 50, stock: 100, status: 'Normal', description: '', packagingImage: '' });
    setShowAddModal(true);
  };

  const openEditModal = (product: RiceProduct) => {
    setEditingId(product.id);
    setNewProduct({ ...product });
    setShowAddModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || !newProduct.origin) return;

    if (editingId) {
        // Update existing
        const updatedProduct: RiceProduct = {
            ...newProduct as RiceProduct,
            id: editingId,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
        };
        onUpdateProduct(updatedProduct);
    } else {
        // Add new
        const productToAdd: RiceProduct = {
            id: `R${Math.floor(Math.random() * 10000).toString().padStart(3, '0')}`,
            name: newProduct.name!,
            origin: newProduct.origin!,
            price: newProduct.price || 0,
            weight: newProduct.weight || 5,
            textureScore: newProduct.textureScore || 50,
            aromaScore: newProduct.aromaScore || 50,
            stock: newProduct.stock || 0,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
            description: newProduct.description || '暂无描述',
            matchReason: '',
            tags: [],
            packagingImage: newProduct.packagingImage,
        };
        onAddProduct(productToAdd);
    }

    setShowAddModal(false);
    // Reset form
    setNewProduct({ name: '', origin: '', price: 0, textureScore: 50, aromaScore: 50, stock: 100, status: 'Normal', description: '', packagingImage: '' });
  };

  // --- User Management Handlers ---

  const handleUserInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setUserForm(prev => ({ ...prev, [name]: value }));
  };

  const openAddUserModal = () => {
    setEditingUserId(null);
    setUserForm({ username: '', role: 'Registered', status: 'Active' });
    setShowUserModal(true);
  };

  const openEditUserModal = (user: UserProfile) => {
    setEditingUserId(user.id);
    setUserForm({ username: user.username, role: user.role, status: user.status });
    setShowUserModal(true);
  };

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userForm.username) return;

    if (editingUserId) {
        // Update User
        onUpdateUsers(users.map(u => u.id === editingUserId ? { ...u, ...userForm } as UserProfile : u));
    } else {
        // Add User
        const newUser: UserProfile = {
            id: `U${Math.floor(Math.random() * 10000)}`,
            username: userForm.username!,
            role: userForm.role as 'Guest' | 'Registered',
            status: userForm.status as 'Active' | 'Banned',
            ip: `192.168.1.${Math.floor(Math.random() * 255)}`, // Mock IP
            lastActive: 'Just now',
            requestCount: 0,
            favorites: []
        };
        onUpdateUsers([newUser, ...users]);
    }
    setShowUserModal(false);
  };

  const toggleUserStatus = (userId: string) => {
      onUpdateUsers(users.map(user => {
          if (user.id === userId) {
              return { ...user, status: user.status === 'Active' ? 'Banned' : 'Active' };
          }
          return user;
      }));
  };

  const filteredUsers = users.filter(u => 
    u.username.toLowerCase().includes(userSearch.toLowerCase()) || 
    u.id.toLowerCase().includes(userSearch.toLowerCase())
  );

  // Filter Inventory based on search
  const filteredInventory = inventory.filter(item => 
    item.name.toLowerCase().includes(productSearch.toLowerCase()) || 
    item.origin.toLowerCase().includes(productSearch.toLowerCase()) ||
    item.id.toLowerCase().includes(productSearch.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col relative">
