                              <td colSpan={8} className="px-6 py-12 text-center text-gray-500">
                                  <div className="flex flex-col items-center justify-center">
                                      <Search className="w-8 h-8 text-gray-300 mb-2" />
                                      <p>未找到匹配的稻米数据</p>
                                  </div>
                              </td>
                          </tr>
