// Fix: Use correct import and remove prohibited/deprecated types
import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceTexture, RiceGrainLength, RiceProduct } from "../types";

// 初始化 Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 定义 AI 返回的 JSON 架构
const recommendationSchema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "基于数据库特征的具体匹配理由" },
          confidence: { type: Type.NUMBER, description: "匹配置信度 (0-100)" }
        },
        required: ["id", "matchReason", "confidence"],
      },
    },
    analysis: {
      type: Type.STRING,
      description: "针对该用户需求的综合检索策略报告。",
    },
  },
  required: ["recommendations", "analysis"],
};

/**
 * 本地召回检索算法 (Recall Stage)
 * 从 500 条数据中筛选出最相关的 50 条，用于 AI 进一步分析
 */
const localRecall = (prefs: UserPreferences, inventory: RiceProduct[]): RiceProduct[] => {
  return inventory
    .map(item => {
      let score = 0;

      // 1. 价格区间匹配 (权重: 30)
      if (prefs.maxPrice && item.price <= prefs.maxPrice && item.price >= (prefs.minPrice || 0)) {
        score += 30;
      } else if (prefs.maxPrice && item.price <= prefs.maxPrice * 1.3) {
        score += 15; // 稍微超出预算也能接受
      }

      // 2. 产地相关性 (权重: 20)
      if (prefs.origin && item.origin.includes(prefs.origin)) {
        score += 20;
      }

      // 3. 口感特征匹配 (权重: 25)
      if (prefs.texture === RiceTexture.SOFT && item.textureScore > 70) score += 25;
      if (prefs.texture === RiceTexture.FIRM && item.textureScore < 40) score += 25;
      if (prefs.texture === RiceTexture.BALANCED && item.textureScore >= 40 && item.textureScore <= 70) score += 25;

      // 4. 香气匹配 (权重: 15)
      if (prefs.aroma && item.aromaScore > 60) score += 15;

      // 5. 关键词搜索 (权重: 10)
      if (prefs.requirements && (
          item.description?.includes(prefs.requirements) || 
          item.name.includes(prefs.requirements)
      )) {
          score += 10;
      }

      return { ...item, _internalScore: score };
    })
    .sort((a: any, b: any) => b._internalScore - a._internalScore)
    .slice(0, 50); // 仅保留最相关的 50 款
};

const formatInventoryForPrompt = (items: RiceProduct[]) => {
  return items.map(p => 
    `ID:${p.id}|名:${p.name}|价:${p.price}|软:${p.textureScore}|香:${p.aromaScore}|述:${p.description?.substring(0, 25)}`
  ).join('\n');
};

/**
 * 文本偏好推荐：实现精准检索
 */
export const getRiceRecommendations = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  // 1. 本地粗排检索
  const candidates = localRecall(prefs, inventory);
  const inventoryStr = formatInventoryForPrompt(candidates);

  const prompt = `
    作为资深稻米品鉴专家，请从下列【筛选后的数据库子集】中选出最符合用户需求的3款。
    【用户需求】: 产地:${prefs.origin||"不限"}, 预算:${prefs.minPrice}-${prefs.maxPrice}元/kg, 口感:${prefs.texture}, 香气:${prefs.aroma?"必须":"不限"}, 备注:${prefs.requirements}

    【数据库子集】:
    ${inventoryStr}

    请输出 JSON 格式，包含具体的推荐理由（需提及数据库中的具体参数）和匹配置信度。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recommendationSchema,
        temperature: 0.1, 
      },
    });

    const parsedResult = JSON.parse(response.text);

    const recommendations = parsedResult.recommendations
      .map((rec: any) => {
        const originalProduct = inventory.find(p => p.id === rec.id);
        if (!originalProduct) return null;
        return { 
          ...originalProduct, 
          matchReason: rec.matchReason,
          // 将 AI 返回的置信度注入标签，方便前端展示
          tags: [...(originalProduct.tags || []), `匹配度:${rec.confidence}%`]
        };
      })
      .filter((item: any): item is RiceProduct => item !== null);

    return {
        recommendations,
        analysis: parsedResult.analysis
    };

  } catch (error) {
    console.error("Retrieval Error:", error);
    // 降级至本地检索逻辑
    return {
      recommendations: candidates.slice(0, 3).map(c => ({ ...c, matchReason: "基于多维特征向量计算得到的最高分匹配项。" })),
      analysis: "当前 AI 引擎响应缓慢，系统已自动切换至启发式检索算法，确保基础匹配的准确性。"
    };
  }
};

/**
 * 图像多模态推荐：基于视觉特征索引数据库
 */
export const analyzeImageForRice = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  // 图像模式下，随机选择 60 条覆盖不同特征的数据作为检索空间
  const sampleData = inventory.length > 60 ? [...inventory].sort(() => 0.5 - Math.random()).slice(0, 60) : inventory;
  const inventoryStr = formatInventoryForPrompt(sampleData);

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Image } },
          { text: `分析图中食物的口味（如油腻、清淡、酸甜等），并从数据库中选出3款能解腻或提升口感的稻米。\n数据库预览：\n${inventoryStr}` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: recommendationSchema,
        temperature: 0.2
      }
    });

    const parsedResult = JSON.parse(response.text);
    const recommendations = parsedResult.recommendations
     .map((rec: any) => {
       const originalProduct = inventory.find(p => p.id === rec.id);
       if (!originalProduct) return null;
       return { 
         ...originalProduct, 
         matchReason: rec.matchReason,
         tags: [...(originalProduct.tags || []), `视觉匹配:${rec.confidence}%`]
       };
     })
     .filter((item: any): item is RiceProduct => item !== null);

   return {
       recommendations,
       analysis: parsedResult.analysis
   };
  } catch (error) {
    return {
      recommendations: inventory.slice(0, 3).map(c => ({ ...c, matchReason: "默认推荐款，适合搭配大多数菜肴。" })),
      analysis: "图像分析服务暂时不可用。"
    };
  }
}

