import Login from './components/Login';
import AdminDashboard from './components/AdminDashboard';
import UserAuthModal from './components/UserAuthModal';
import { RotateCcw, LogOut, Heart, Search, LogIn } from 'lucide-react';

// --- 数据生成器：构建500条模拟数据 ---
const generateFullInventory = (): RiceProduct[] => {
  const baseProducts: Partial<RiceProduct>[] = [
    { id: 'R001', name: '五常稻花香二号', origin: '黑龙江五常', price: 19.8, weight: 5, textureScore: 88, aromaScore: 95, description: '正宗五常核心产区，米粒细长，煮饭时满屋飘香。' },
    { id: 'R002', name: '泰国茉莉香米', origin: '泰国清莱', price: 12.5, weight: 5, textureScore: 65, aromaScore: 90, description: '进口一级香米，有独特的潘丹叶香味。' },
    { id: 'R003', name: '盘锦蟹田米', origin: '辽宁盘锦', price: 7.8, weight: 10, textureScore: 75, aromaScore: 40, description: '采用蟹稻共生生态种植，米珠圆玉润。' },
    { id: 'R004', name: '增城丝苗米', origin: '广东增城', price: 9.2, weight: 5, textureScore: 45, aromaScore: 60, description: '米中碧玉，成饭爽滑，适合做煲仔饭。' },
    { id: 'R005', name: '日本越光米', origin: '日本新泻', price: 45.0, weight: 2, textureScore: 92, aromaScore: 75, description: '顶级口感，米饭晶莹剔透，粘性极佳。' },
  ];

  const origins = ['黑龙江', '吉林', '辽宁', '江苏', '浙江', '安徽', '湖北', '湖南', '广东', '广西', '四川', '云南', '新疆', '宁夏', '江西', '福建'];
  const prefixes = ['精选', '有机', '生态', '高山', '寒地', '核心产区', '农家', '优质', '特级', '出口级'];
  const suffixes = ['大米', '珍珠米', '长粒香', '丝苗米', '软米', '贡米', '油粘米', '秋田小町', '胚芽米', '糙米'];

  const fullList: RiceProduct[] = [...baseProducts as RiceProduct[]];

  for (let i = fullList.length + 1; i <= 500; i++) {
    const origin = origins[Math.floor(Math.random() * origins.length)];
    const prefix = prefixes[Math.floor(Math.random() * prefixes.length)];
    const suffix = suffixes[Math.floor(Math.random() * suffixes.length)];
    const name = `${origin}${prefix}${suffix}`;

    const price = parseFloat((Math.random() * 25 + 4).toFixed(1));
    const texture = Math.floor(Math.random() * 80 + 20);
    const aroma = Math.floor(Math.random() * 80 + 10);
    const weight = [1, 2, 2.5, 5, 10, 25][Math.floor(Math.random() * 6)];
    const stock = Math.floor(Math.random() * 5000 + 50);

    fullList.push({
      id: `R${i.toString().padStart(3, '0')}`,
      name,
      origin: `${origin}省特定产区`,
      price,
      weight,
      textureScore: texture,
      aromaScore: aroma,
      stock,
      status: stock < 200 ? 'Critical' : stock < 1000 ? 'Low Stock' : 'Normal',
      description: `来自${origin}的${prefix}${suffix}，采用传统耕作方式，${texture > 70 ? '口感软糯' : '米粒分明'}，是您家庭用餐的优质选择。`,
      tags: [prefix, suffix, origin],
      matchReason: ''
    });
  }
  return fullList;
};

const INITIAL_INVENTORY: RiceProduct[] = generateFullInventory();

const INITIAL_USERS: UserProfile[] = [
    { id: 'U1023', username: 'RiceLover_01', ip: '192.168.1.101', role: 'Registered', status: 'Active', lastActive: '2 mins ago', requestCount: 45, favorites: ['R001'] },
    { id: 'U1024', username: 'Guest_882', ip: '192.168.1.105', role: 'Guest', status: 'Active', lastActive: '5 mins ago', requestCount: 12, favorites: [] },
    { id: 'U1027', username: 'Farmer_Li', ip: '10.0.0.5', role: 'Registered', status: 'Active', lastActive: '1 hour ago', requestCount: 89, favorites: [] },
];

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(null);
  const [users, setUsers] = useState<UserProfile[]>(() => {
    const saved = localStorage.getItem('rice_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [inventory, setInventory] = useState<RiceProduct[]>(INITIAL_INVENTORY);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RecommendationResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [viewMode, setViewMode] = useState<'search' | 'favorites'>('search');

  useEffect(() => {
    localStorage.setItem('rice_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    if (currentUser) {
      const updatedUser = users.find(u => u.id === currentUser.id);
      if (updatedUser && JSON.stringify(updatedUser) !== JSON.stringify(currentUser)) {
        setCurrentUser(updatedUser);
      }
    }
  }, [users, currentUser]);

  const handleLoginPortal = (role: UserRole) => {
    setUserRole(role);
    setResults(null); 
    setViewMode('search');
    if (role === 'admin') setCurrentUser(null);
  };

  const handleLogout = () => {
    setUserRole(null);
    setResults(null);
    setCurrentUser(null);
    setViewMode('search');
  };

  const handleAddProduct = (newProduct: RiceProduct) => {
    setInventory(prev => [...prev, newProduct]);
  };

  const handleUpdateProduct = (updatedProduct: RiceProduct) => {
    setInventory(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => {
      setUsers(updatedUsers);
  };

  const handleClientRegister = (username: string, password?: string) => {
    if (users.some(u => u.username === username)) {
      throw new Error("用户名已存在");
    }
    const newUser: UserProfile = {
      id: `U${Date.now()}`,
      username,
      password, 
      role: 'Registered',
      status: 'Active',
      ip: '127.0.0.1', 
      lastActive: 'Just now',
      requestCount: 0,
      favorites: []
    };
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  };

  const handleClientLogin = (username: string, password?: string) => {
    const user = users.find(u => u.username === username && u.password === password && u.status === 'Active');
    if (!user) {
      throw new Error("用户名或密码错误，或账号已被封禁");
    }
    setCurrentUser(user);
  };

  const toggleFavorite = (productId: string) => {
    if (!currentUser) {
      setShowAuthModal(true);
      return;
    }
    setUsers(prevUsers => prevUsers.map(u => {
      if (u.id === currentUser.id) {
        const isFav = u.favorites.includes(productId);
        return { ...u, favorites: isFav ? u.favorites.filter(id => id !== productId) : [...u.favorites, productId] };
      }
      return u;
    }));
  };

  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    setViewMode('search');
    try {
      const data = await getRiceRecommendations(prefs, inventory);
      setResults(data);
    } catch (err) {
      setError("系统繁忙，请稍后再试或检查您的网络连接。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    setViewMode('search');
    try {
      const data = await analyzeImageForRice(base64, inventory);
      setResults(data);
    } catch (err) {
      setError("图片分析失败，请重试。");
    } finally {
      setIsLoading(false);
    }
  }

  const reset = () => {
    setResults(null);
    setViewMode('search');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const favoriteProducts = currentUser 
    ? inventory.filter(p => currentUser.favorites.includes(p.id))
    : [];

  if (!userRole) {
    return <Login onLogin={handleLoginPortal} />;
  }

  if (userRole === 'admin') {
    return (
      <AdminDashboard 
        onLogout={handleLogout} 
        inventory={inventory}
        onAddProduct={handleAddProduct}
        onUpdateProduct={handleUpdateProduct}
        users={users}
        onUpdateUsers={handleUpdateUsers}
      />
    );
  }

  return (
    <div className="min-h-screen bg-[#fafafa] text-gray-900 font-sans selection:bg-emerald-100 relative">
      {/* 顶部导航：使用 fixed 并增加背景模糊，避免遮挡内容 */}
      <nav className="fixed top-0 left-0 w-full p-4 flex justify-between items-center z-[80] transition-all bg-white/60 backdrop-blur-md border-b border-gray-100 shadow-sm">
          <div className="flex items-center gap-3">
             {!currentUser ? (
               <button 
                 onClick={() => setShowAuthModal(true)}
                 className="flex items-center gap-2 bg-emerald-600 shadow-md shadow-emerald-200 px-5 py-2 rounded-full text-sm font-bold text-white hover:bg-emerald-700 transition-all active:scale-95"
               >
                 <LogIn className="w-4 h-4" />
                 登录 / 注册
               </button>
             ) : (
                <div className="flex items-center gap-2">
                   <div className="flex items-center gap-2 bg-gray-100 px-4 py-2 rounded-full text-xs font-bold text-gray-700">
                      <div className="w-5 h-5 bg-emerald-500 text-white rounded-full flex items-center justify-center text-[10px]">
                        {currentUser.username.charAt(0).toUpperCase()}
                      </div>
                      Hi, {currentUser.username}
                   </div>
                   <button 
                      onClick={() => setViewMode(viewMode === 'search' ? 'favorites' : 'search')}
                      className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all shadow-sm border ${viewMode === 'favorites' ? 'bg-red-500 text-white border-red-500 shadow-red-200' : 'bg-white text-gray-600 border-gray-200 hover:text-red-500 active:scale-95'}`}
                   >
                      <Heart className={`w-3.5 h-3.5 ${viewMode === 'favorites' ? 'fill-current' : ''}`} />
                      收藏 ({currentUser.favorites.length})
                   </button>
                </div>
             )}
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={handleLogout}
              className="text-[10px] text-gray-400 hover:text-red-500 flex items-center gap-1 transition-colors px-3 py-2 rounded-lg hover:bg-red-50 font-bold"
            >
              <LogOut className="w-3 h-3" />
              退出登录
            </button>
          </div>
      </nav>

      <div className="w-full max-w-[1600px] mx-auto px-4 md:px-8 pt-24 pb-12">
        {viewMode === 'favorites' && currentUser ? (
           <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-8">
                 <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
                    <Heart className="w-8 h-8 text-red-500 fill-red-500" />
                    我的收藏夹
                 </h2>
                 <button onClick={() => setViewMode('search')} className="text-sm font-bold text-emerald-600 hover:text-emerald-700 underline underline-offset-4 decoration-2">
                    返回搜索推荐
                 </button>
              </div>
              <ResultsGrid 
                  products={favoriteProducts} 
                  analysisText="" 
                  favorites={currentUser.favorites} 
                  onToggleFavorite={toggleFavorite}
                  showAnalysis={false}
              />
           </div>
        ) : (
          <>
            <div className={`transition-all duration-700 ${results ? 'mb-12' : 'flex flex-col items-center justify-center min-h-[70vh]'}`}>
                <div className="w-full max-w-3xl mx-auto">
                    <Hero />
                    {!results && (
                        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 w-full">
                            <PreferenceForm 
                                onSubmitPreferences={handlePreferenceSubmit} 
                                onSubmitImage={handleImageSubmit}
                                isLoading={isLoading} 
                            />
                            {error && (
                                <div className="mt-6 p-5 bg-red-50 border border-red-100 text-red-600 text-sm rounded-2xl text-center shadow-sm">
                                    {error}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {results && (
                <div className="w-full animate-in fade-in slide-in-from-bottom-12 duration-1000 space-y-8">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white/40 backdrop-blur p-4 rounded-3xl border border-white/50 shadow-sm">
                        <div className="flex flex-col">
                           <h2 className="text-2xl font-black text-gray-900 flex items-center gap-3">
                              <Search className="w-7 h-7 text-emerald-600" /> 
                              为您找到的推荐
                           </h2>
                           <p className="text-xs text-gray-400 mt-1 pl-10">已从 {inventory.length} 款优质稻米中为您精准筛选</p>
                        </div>
                        <button 
                            onClick={reset}
                            className="flex items-center justify-center gap-2 text-sm font-bold text-gray-500 hover:text-emerald-600 transition-all px-6 py-2.5 rounded-full hover:bg-white bg-gray-50/50 shadow-sm border border-transparent hover:border-emerald-100 active:scale-95"
                        >
                            <RotateCcw className="w-4 h-4" />
                            重置筛选条件
                        </button>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-1 gap-8">
                       <AnalysisChart products={results.recommendations} />
                       <ResultsGrid 
                          products={results.recommendations} 
                          analysisText={results.analysis} 
                          favorites={currentUser?.favorites || []}
                          onToggleFavorite={toggleFavorite}
                       />
                    </div>

                    <footer className="text-center pt-16 pb-8">
                        <div className="inline-block px-4 py-2 bg-gray-50 rounded-full border border-gray-100">
                          <p className="text-[10px] text-gray-400 font-mono">© 2024 RiceRec Project · GradDesign Demo · DB Ver: 2.1.0 · Active Items: {inventory.length}</p>
                        </div>
                    </footer>
                </div>
            )}
          </>
        )}
      </div>

      {showAuthModal && (
        <UserAuthModal 
           onClose={() => setShowAuthModal(false)}
           onLogin={handleClientLogin}
           onRegister={handleClientRegister}
        />
      )}
    </div>
  );
};

export default App;

{
  "name": "稻米个性化推荐系统",
  "description": "基于多模态AI的智能稻米推荐系统",
  "requestFramePermissions": []
}

// 修复：使用正确的导入并移除已弃用类型
import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceProduct } from "../types";

// 初始化 Gemini API
const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// 定义 AI 返回的 JSON 架构
const recommendationSchema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "推荐理由" }
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: { type: Type.STRING },
  },
  required: ["recommendations", "analysis"],
};

/**
 * 指数退避重试辅助函数
 */
async function withRetry<T>(
  fn: () => Promise<T>,
  retries: number = 3,
  delay: number = 1000
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries <= 0) throw error;

    const errorMessage = error.message || "";
    const isTransient = 
      errorMessage.includes("500") || 
      errorMessage.includes("Rpc failed") || 
      errorMessage.includes("xhr error") ||
      errorMessage.includes("UNKNOWN");

    if (isTransient) {
      console.warn(`检测到瞬时错误，将在 ${delay} 毫秒后重试... (剩余重试次数: ${retries})`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

const formatInventoryForPrompt = (items: RiceProduct[]) => {
  return items.slice(0, 150).map(p => 
    `编号:${p.id}|名称:${p.name}|价格:${p.price}|产地:${p.origin}`
  ).join('\n');
};

/**
 * 文本偏好推荐
 */
export const getRiceRecommendations = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const inventoryStr = formatInventoryForPrompt(inventory);
  const ai = getAIClient();

  const prompt = `
    作为资深稻米专家，请从以下数据库中选出最符合用户需求的3款稻米。
    用户需求：产地:${prefs.origin||"不限"}, 预算:${prefs.minPrice}-${prefs.maxPrice}元/kg, 口感:${prefs.texture}, 备注:${prefs.requirements}

    数据库：
    ${inventoryStr}

    请严格返回 JSON 格式数据。
  `;

  try {
    const response = await withRetry(async () => {
      return await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: recommendationSchema,
        },
      });
    });

    const parsedResult = JSON.parse(response.text || "{}");
    const recommendations = (parsedResult.recommendations || [])
      .map((rec: any) => {
        const product = inventory.find(p => p.id === rec.id);
        return product ? { ...product, matchReason: rec.matchReason } : null;
      })
      .filter((item: any) => item !== null);

    return { 
      recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
      analysis: parsedResult.analysis || "基于您的偏好进行了精选推荐。" 
    };
  } catch (error: any) {
    console.error("Gemini API 错误 (文本):", error);
    return { 
      recommendations: inventory.slice(0, 3), 
      analysis: "推荐引擎暂时响应异常，系统已为您展示热门库内产品。错误详情: " + (error.message || "未知错误")
    };
  }
};

/**
 * 图像多模态推荐
 */
export const analyzeImageForRice = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const inventoryStr = formatInventoryForPrompt(inventory);
  const ai = getAIClient();

  try {
    const response = await withRetry(async () => {
      return await ai.models.generateContent({
        model: "gemini-3-flash-preview", 
        contents: {
          parts: [
            { inlineData: { mimeType: "image/jpeg", data: base64Image } },
            { text: `分析图中菜肴的口味特征（如：油腻、清淡、酸甜），并从以下稻米数据库中选出3款能与之完美搭配的稻米产品：\n${inventoryStr}` }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: recommendationSchema,
        }
      });
    });

    const parsedResult = JSON.parse(response.text || "{}");
    const recommendations = (parsedResult.recommendations || [])
     .map((rec: any) => {
       const product = inventory.find(p => p.id === rec.id);
       return product ? { ...product, matchReason: rec.matchReason } : null;
     })
     .filter((item: any) => item !== null);

   return { 
     recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
     analysis: parsedResult.analysis || "已根据图片分析结果为您匹配最佳大米。" 
   };
  } catch (error: any) {
    console.error("Gemini API 错误 (图像):", error);
    return { 
      recommendations: inventory.slice(0, 3), 
      analysis: "图像解析服务暂时不可用，请稍后再试。错误详情: " + (error.message || "未知错误")
    };
  }
}

import React from 'react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, Tooltip } from 'recharts';
import { RiceProduct } from '../types';

interface AnalysisChartProps {
  products: RiceProduct[];
}

const AnalysisChart: React.FC<AnalysisChartProps> = ({ products }) => {
  const topProducts = products.slice(0, 3);

  const chartData = [
    { subject: '软糯度', A: topProducts[0]?.textureScore || 0, B: topProducts[1]?.textureScore || 0, C: topProducts[2]?.textureScore || 0, fullMark: 100 },
    { subject: '米香值', A: topProducts[0]?.aromaScore || 0, B: topProducts[1]?.aromaScore || 0, C: topProducts[2]?.aromaScore || 0, fullMark: 100 },
    { subject: '性价比', A: topProducts[0] ? Math.min(100, 1000 / topProducts[0].price) : 0, B: topProducts[1] ? Math.min(100, 1000 / topProducts[1].price) : 0, C: topProducts[2] ? Math.min(100, 1000 / topProducts[2].price) : 0, fullMark: 100 },
    { subject: '大众口碑', A: 90, B: 85, C: 88, fullMark: 100 },
    { subject: '营养成分', A: 85, B: 80, C: 92, fullMark: 100 },
  ];

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col md:flex-row items-center">
      <div className="flex-1 w-full">
         <h3 className="text-sm font-bold text-gray-900 mb-4 uppercase tracking-wider">多模态特征分析图谱</h3>
         <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
            <RadarChart cx="50%" cy="50%" outerRadius="75%" data={chartData}>
                <PolarGrid stroke="#f1f5f9" />
                <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 11 }} />
                <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />

                {topProducts.map((p, idx) => (
                    <Radar
                        key={p.id}
                        name={p.name}
                        dataKey={idx === 0 ? "A" : idx === 1 ? "B" : "C"}
                        stroke={idx === 0 ? "#059669" : idx === 1 ? "#0ea5e9" : "#d97706"}
                        strokeWidth={2}
                        fill={idx === 0 ? "#059669" : idx === 1 ? "#0ea5e9" : "#d97706"}
                        fillOpacity={0.1}
                    />
                ))}
                <Tooltip 
                    formatter={(value: any, name: any) => [value, name]}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)', fontSize: '12px' }}
                />
            </RadarChart>
            </ResponsiveContainer>
         </div>
      </div>

      <div className="md:w-1/3 w-full mt-4 md:mt-0 md:pl-6 border-t md:border-t-0 md:border-l border-gray-100 pt-4 md:pt-0">
          <div className="space-y-3">
            <h4 className="text-[10px] font-bold text-gray-400 uppercase mb-2">对比产品列表</h4>
            {topProducts.map((p, idx) => (
                <div key={p.id} className="flex items-center text-xs font-medium text-gray-600">
                    <span className={`w-2.5 h-2.5 rounded-full mr-2 flex-shrink-0 ${idx === 0 ? 'bg-emerald-600' : idx === 1 ? 'bg-sky-500' : 'bg-amber-500'}`}></span>
                    <span className="truncate">{p.name}</span>
                </div>
            ))}
          </div>
