import React, { useState } from 'react';
import { X, UserPlus, LogIn, AlertCircle } from 'lucide-react';

interface UserAuthModalProps {
  onClose: () => void;
  onLogin: (username: string, password?: string) => void;
  onRegister: (username: string, password?: string) => void;
}

const UserAuthModal: React.FC<UserAuthModalProps> = ({ onClose, onLogin, onRegister }) => {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) {
      setError("请输入完整的账号和密码");
      return;
    }

    try {
      if (mode === 'login') {
        onLogin(username, password);
      } else {
        onRegister(username, password);
      }
      onClose();
    } catch (err: any) {
      setError(err.message || "登录过程中发生未知错误");
    }
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
        <div className="px-6 py-5 border-b border-gray-100 flex justify-between items-center bg-emerald-50/30">
          <h3 className="font-bold text-gray-900">
            {mode === 'login' ? '系统登录' : '创建个人账号'}
          </h3>
          <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 transition-colors bg-white/50 rounded-full">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">登录用户名</label>
            <input
              type="text"
              value={username}
              onChange={(e) => { setUsername(e.target.value); setError(''); }}
              className="w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm focus:ring-2 focus:ring-emerald-500 transition-all placeholder-gray-300"
              placeholder="请输入您的账号"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">账户密码</label>
            <input
              type="password"
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className="w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm focus:ring-2 focus:ring-emerald-500 transition-all placeholder-gray-300"
              placeholder="请输入您的密码"
            />
          </div>

          {error && (
            <div className="flex items-center gap-2 text-xs text-red-600 bg-red-50 p-3.5 rounded-xl border border-red-100">
              <AlertCircle className="w-4 h-4 flex-shrink-0" />
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold hover:bg-emerald-700 transition-all flex justify-center items-center gap-2 shadow-xl shadow-emerald-200 active:scale-95"
          >
            {mode === 'login' ? (
              <>
                <LogIn className="w-4 h-4" /> 确认登录
              </>
            ) : (
              <>
                <UserPlus className="w-4 h-4" /> 立即注册
              </>
            )}
          </button>

          <div className="text-center pt-2">
            <button
              type="button"
              onClick={() => {
                setMode(mode === 'login' ? 'register' : 'login');
                setError('');
              }}
              className="text-xs text-emerald-600 hover:text-emerald-700 font-bold transition-colors"
            >
              {mode === 'login' ? '还没有账号？前往注册' : '已有系统账号？前往登录'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

