    setViewMode('search');
  };

  const handleAddProduct = (newProduct: RiceProduct) => {
    setInventory(prev => [...prev, newProduct]);
  };

  const handleUpdateProduct = (updatedProduct: RiceProduct) => {
    setInventory(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => {
      setUsers(updatedUsers);
  };

  const handleClientRegister = (username: string, password?: string) => {
    if (users.some(u => u.username === username)) {
      throw new Error("该账号名已被占用");
    }
    const newUser: UserProfile = {
      id: `U${Date.now()}`,
      username,
      password, 
      role: 'Registered',
      status: 'Active',
      ip: '127.0.0.1', 
      lastActive: '刚刚',
      requestCount: 0,
      favorites: []
    };
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  };

  const handleClientLogin = (username: string, password?: string) => {
    const user = users.find(u => u.username === username && u.password === password && u.status === 'Active');
    if (!user) {
      throw new Error("账号密码错误，或账户已被锁定");
    }
    setCurrentUser(user);
  };

  const toggleFavorite = (productId: string) => {
    if (!currentUser) {
      setShowAuthModal(true);
      return;
    }
    setUsers(prevUsers => prevUsers.map(u => {
      if (u.id === currentUser.id) {
        const isFav = u.favorites.includes(productId);
        return { ...u, favorites: isFav ? u.favorites.filter(id => id !== productId) : [...u.favorites, productId] };
      }
      return u;
    }));
  };

  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    setViewMode('search');
    try {
      const data = await getRiceRecommendations(prefs, inventory);
      setResults(data);
    } catch (err) {
      setError("AI 引擎暂时无法连接，请稍后再试。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    setViewMode('search');
    try {
      const data = await analyzeImageForRice(base64, inventory);
      setResults(data);
    } catch (err) {
      setError("图片智能解析失败，请确保网络通畅。");
    } finally {
      setIsLoading(false);
    }
  }

  const reset = () => {
    setResults(null);
    setViewMode('search');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const favoriteProducts = currentUser 
    ? inventory.filter(p => currentUser.favorites.includes(p.id))
    : [];

  if (!userRole) {
    return <Login onLogin={handleLoginPortal} />;
  }

  if (userRole === 'admin') {
    return (
      <AdminDashboard 
        onLogout={handleLogout} 
        inventory={inventory}
        onAddProduct={handleAddProduct}
        onUpdateProduct={handleUpdateProduct}
        users={users}
        onUpdateUsers={handleUpdateUsers}
      />
    );
  }

  return (
    <div className="min-h-screen bg-[#fafafa] text-gray-900 font-sans selection:bg-emerald-100 relative">
      <nav className="fixed top-0 left-0 w-full p-4 flex justify-between items-center z-[80] transition-all bg-white/60 backdrop-blur-md border-b border-gray-100 shadow-sm">
          <div className="flex items-center gap-3">
             {!currentUser ? (
               <button 
                 onClick={() => setShowAuthModal(true)}
                 className="flex items-center gap-2 bg-emerald-600 shadow-md shadow-emerald-200 px-5 py-2 rounded-full text-sm font-bold text-white hover:bg-emerald-700 transition-all active:scale-95"
               >
                 <LogIn className="w-4 h-4" />
                 登录系统 / 注册
               </button>
             ) : (
                <div className="flex items-center gap-2">
                   <div className="flex items-center gap-2 bg-gray-100 px-4 py-2 rounded-full text-xs font-bold text-gray-700">
                      <div className="w-5 h-5 bg-emerald-500 text-white rounded-full flex items-center justify-center text-[10px]">
                        {currentUser.username.charAt(0).toUpperCase()}
                      </div>
                      你好，{currentUser.username}
                   </div>
                   <button 
                      onClick={() => setViewMode(viewMode === 'search' ? 'favorites' : 'search')}
                      className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all shadow-sm border ${viewMode === 'favorites' ? 'bg-red-500 text-white border-red-500 shadow-red-200' : 'bg-white text-gray-600 border-gray-200 hover:text-red-500 active:scale-95'}`}
                   >
                      <Heart className={`w-3.5 h-3.5 ${viewMode === 'favorites' ? 'fill-current' : ''}`} />
                      收藏夹 ({currentUser.favorites.length})
                   </button>
                </div>
             )}
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={handleLogout}
              className="text-[10px] text-gray-400 hover:text-red-500 flex items-center gap-1 transition-colors px-3 py-2 rounded-lg hover:bg-red-50 font-bold"
            >
              <LogOut className="w-3 h-3" />
              退出系统
            </button>
          </div>
      </nav>

      <div className="w-full max-w-[1600px] mx-auto px-4 md:px-8 pt-24 pb-12">
        {viewMode === 'favorites' && currentUser ? (
           <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-8">
                 <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
                    <Heart className="w-8 h-8 text-red-500 fill-red-500" />
                    我的收藏夹
                 </h2>
                 <button onClick={() => setViewMode('search')} className="text-sm font-bold text-emerald-600 hover:text-emerald-700 underline underline-offset-4 decoration-2">
                    返回搜索推荐页面
                 </button>
              </div>
              <ResultsGrid 
                  products={favoriteProducts} 
                  analysisText="" 
                  favorites={currentUser.favorites} 
                  onToggleFavorite={toggleFavorite}
                  showAnalysis={false}
              />
           </div>
        ) : (
          <>
            <div className={`transition-all duration-700 ${results ? 'mb-12' : 'flex flex-col items-center justify-center min-h-[70vh]'}`}>
                <div className="w-full max-w-3xl mx-auto">
                    <Hero />
                    {!results && (
                        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 w-full">
                            <PreferenceForm 
                                onSubmitPreferences={handlePreferenceSubmit} 
                                onSubmitImage={handleImageSubmit}
                                isLoading={isLoading} 
                            />
                            {error && (
                                <div className="mt-6 p-5 bg-red-50 border border-red-100 text-red-600 text-sm rounded-2xl text-center shadow-sm">
                                    {error}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {results && (
                <div className="w-full animate-in fade-in slide-in-from-bottom-12 duration-1000 space-y-8">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white/40 backdrop-blur p-4 rounded-3xl border border-white/50 shadow-sm">
                        <div className="flex flex-col">
                           <h2 className="text-2xl font-black text-gray-900 flex items-center gap-3">
                              <Search className="w-7 h-7 text-emerald-600" /> 
                              为您精选的推荐结果
                           </h2>
                           <p className="text-xs text-gray-400 mt-1 pl-10">已从数据库中为您精准匹配出最合适的 3 款稻米</p>
                        </div>
                        <button 
                            onClick={reset}
                            className="flex items-center justify-center gap-2 text-sm font-bold text-gray-500 hover:text-emerald-600 transition-all px-6 py-2.5 rounded-full hover:bg-white bg-gray-50/50 shadow-sm border border-transparent hover:border-emerald-100 active:scale-95"
                        >
                            <RotateCcw className="w-4 h-4" />
                            重新开始匹配
                        </button>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-1 gap-8">
                       <AnalysisChart products={results.recommendations} />
                       <ResultsGrid 
                          products={results.recommendations} 
                          analysisText={results.analysis} 
                          favorites={currentUser?.favorites || []}
                          onToggleFavorite={toggleFavorite}
                       />
                    </div>

                    <footer className="text-center pt-16 pb-8">
                        <div className="inline-block px-4 py-2 bg-gray-50 rounded-full border border-gray-100">
                          <p className="text-[10px] text-gray-400 font-mono">© 2024 稻米个性化推荐系统 · 计算机专业毕业设计演示 · 数据库版本: 2.1.0 · 活跃稻米数量: {inventory.length}</p>
                        </div>
                    </footer>
                </div>
            )}
          </>
        )}
      </div>

      {showAuthModal && (
        <UserAuthModal 
           onClose={() => setShowAuthModal(false)}
           onLogin={handleClientLogin}
           onRegister={handleClientRegister}
        />
      )}
    </div>
  );
};

export default App;

