      </main>

      {/* 3. 右侧预览面板 */}
      <aside className="w-[340px] bg-gray-50/50 p-6 h-screen flex-shrink-0 z-40 hidden xl:block border-l border-gray-100">
        <PreviewPanel 
          product={previewProduct} 
          isFavorite={!!previewProduct && (currentUser?.favorites.includes(previewProduct.id) || false)}
          onToggleFavorite={toggleFavorite}
        />
      </aside>

      {showAuthModal && (
        <UserAuthModal 
            initialMode={authConfig.mode}
            initialRole={authConfig.role}
            onClose={() => setShowAuthModal(false)} 
            onLogin={handleClientLogin} 
            onRegister={handleClientRegister} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, ChangeEvent } from 'react';
import { UserPreferences, RiceTexture, RiceGrainLength } from '../types';
import { Sliders, Camera, UploadCloud, Loader2, Check, FileCheck, Coins, MapPin, Sparkles, Utensils } from 'lucide-react';

interface PreferenceFormProps {
  onSubmitPreferences: (prefs: UserPreferences) => void;
  onSubmitImage: (base64: string) => void;
  isLoading: boolean;
}

const PreferenceForm: React.FC<PreferenceFormProps> = ({ onSubmitPreferences, onSubmitImage, isLoading }) => {
  const [mode, setMode] = useState<'text' | 'image'>('text');
  const [formData, setFormData] = useState<UserPreferences>({
    minPrice: 0,
    maxPrice: 30,
    requirements: '',
    texture: RiceTexture.BALANCED,
    grainLength: RiceGrainLength.SHORT,
    aroma: false,
  });
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleTextureSelect = (val: RiceTexture) => {
    setFormData(prev => ({ ...prev, texture: val }));
  }

  const handleGrainSelect = (val: RiceGrainLength) => {
    setFormData(prev => ({ ...prev, grainLength: val }));
  }

  const toggleAroma = () => {
    setFormData(prev => ({ ...prev, aroma: !prev.aroma }));
  }

  const handleImageUpload = (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'text') {
        onSubmitPreferences(formData);
    } else {
        if (selectedImage) {
            const base64Data = selectedImage.split(',')[1];
            onSubmitImage(base64Data);
        }
    }
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl shadow-gray-200/50 border border-gray-100 animate-in zoom-in-95 duration-500">
      {/* 模式切换 */}
      <div className="flex justify-center mb-10">
        <div className="bg-gray-100 p-1.5 rounded-2xl inline-flex shadow-inner">
          <button
            className={`px-8 py-3 rounded-xl text-sm font-black transition-all flex items-center gap-3 ${mode === 'text' ? 'bg-white text-emerald-700 shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
            onClick={() => setMode('text')}
          >
            <Sliders className="w-4 h-4" />
            参数匹配模式
          </button>
          <button
            className={`px-8 py-3 rounded-xl text-sm font-black transition-all flex items-center gap-3 ${mode === 'image' ? 'bg-white text-emerald-700 shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
            onClick={() => setMode('image')}
          >
            <Camera className="w-4 h-4" />
            视觉配米模式
          </button>
        </div>
      </div>

      {mode === 'text' ? (
        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* 产地 */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[11px] font-black text-gray-400 uppercase tracking-widest">
                <MapPin className="w-3 h-3" /> 指定产地
              </label>
              <input
                type="text"
                name="origin"
                placeholder="搜索产地，如：黑龙江、泰国..."
                className="w-full bg-gray-50 border-transparent rounded-2xl px-5 py-4 text-sm font-bold text-gray-900 placeholder-gray-400 focus:bg-white focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all shadow-sm"
                value={formData.origin || ''}
                onChange={handleInputChange}
              />
            </div>

            {/* 价格 */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[11px] font-black text-gray-400 uppercase tracking-widest">
                <Coins className="w-3 h-3" /> 价格区间 (元/公斤)
              </label>
              <div className="flex items-center gap-3">
                <input
                  type="number"
                  name="minPrice"
                  placeholder="最低价"
                  className="w-full bg-gray-50 border-transparent rounded-2xl px-4 py-4 text-sm font-bold text-gray-900 focus:bg-white focus:ring-2 focus:ring-emerald-500 transition-all shadow-sm text-center"
                  value={formData.minPrice}
                  onChange={handleInputChange}
                />
                <span className="text-gray-300 font-black">/</span>
                <input
                  type="number"
                  name="maxPrice"
                  placeholder="最高价"
                  className="w-full bg-gray-50 border-transparent rounded-2xl px-4 py-4 text-sm font-bold text-gray-900 focus:bg-white focus:ring-2 focus:ring-emerald-500 transition-all shadow-sm text-center"
                  value={formData.maxPrice}
                  onChange={handleInputChange}
                />
              </div>
            </div>

            {/* 口感 */}
            <div className="md:col-span-2 space-y-3">
                <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                  <Sparkles className="w-3 h-3" /> 口感硬度偏好
                </label>
                <div className="grid grid-cols-3 gap-4">
                    {[
                        { val: RiceTexture.SOFT, label: '绵软糯口' },
                        { val: RiceTexture.BALANCED, label: '软硬适中' },
                        { val: RiceTexture.FIRM, label: 'Q弹韧性' }
                    ].map((opt) => (
                        <button
                            key={opt.val}
                            type="button"
                            onClick={() => handleTextureSelect(opt.val)}
                            className={`py-3 px-4 rounded-2xl text-xs font-black border-2 transition-all ${formData.texture === opt.val ? 'bg-emerald-50 border-emerald-500 text-emerald-700 shadow-md shadow-emerald-50' : 'bg-white border-gray-100 text-gray-500 hover:border-gray-200'}`}
                        >
                            {opt.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* 形态与香气 */}
            <div className="md:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                     <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">米粒物理形态</label>
                     <div className="flex bg-gray-100 p-1 rounded-2xl">
                        {[
                            { val: RiceGrainLength.SHORT, label: '圆粒型' },
                            { val: RiceGrainLength.MEDIUM, label: '中粒型' },
                            { val: RiceGrainLength.LONG, label: '细长型' }
                        ].map((opt) => (
                             <button
                                key={opt.val}
                                type="button"
                                onClick={() => handleGrainSelect(opt.val)}
                                className={`flex-1 py-3 text-[10px] rounded-xl font-black transition-all ${formData.grainLength === opt.val ? 'bg-white shadow-lg text-emerald-700' : 'text-gray-400 hover:text-gray-600'}`}
                             >
                                 {opt.label}
                             </button>
                        ))}
                     </div>
                </div>

                 <div className="space-y-3">
                     <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">芳香物质偏好</label>
                     <button
                        type="button"
                        onClick={toggleAroma}
                        className={`w-full py-3.5 px-6 rounded-2xl border-2 text-xs font-black flex items-center justify-between transition-all ${formData.aroma ? 'bg-amber-50 border-amber-400 text-amber-700 shadow-md shadow-amber-50' : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}`}
                     >
                         <span className="flex items-center gap-2">
                           {formData.aroma ? <Sparkles className="w-3.5 h-3.5" /> : null}
                           要求浓郁米香味
                         </span>
                         {formData.aroma && <Check className="w-4 h-4" />}
                     </button>
                </div>
            </div>

            {/* 补充说明 */}
            <div className="md:col-span-2 space-y-2">
               <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                 <Utensils className="w-3 h-3" /> 使用场景与附加说明
               </label>
               <textarea
                name="requirements"
                rows={3}
                placeholder="例如：准备做蛋炒饭用，或者给一周岁宝宝煮粥用..."
                className="w-full bg-gray-50 border-transparent rounded-2xl px-5 py-4 text-sm font-medium text-gray-900 placeholder:text-gray-300 focus:bg-white focus:ring-2 focus:ring-emerald-500 transition-all resize-none shadow-sm"
                value={formData.requirements || ''}
                onChange={handleInputChange}
              />
            </div>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-emerald-700 transition-all disabled:opacity-50 flex justify-center items-center shadow-xl shadow-emerald-200 mt-4 active:scale-95"
          >
            {isLoading ? <Loader2 className="animate-spin w-5 h-5 mr-3"/> : null}
            {isLoading ? '特征融合模型计算中...' : '启动智能特征分析'}
          </button>
        </form>
      ) : (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="text-center mb-6">
            <h3 className="text-xl font-black text-gray-900">视觉口味分析引擎</h3>
            <p className="text-gray-400 text-xs font-medium mt-1">上传您的菜肴图片，AI 将推荐最佳配米</p>
          </div>

          <label 
              htmlFor="file-upload" 
              className={`flex flex-col items-center justify-center w-full h-64 border-4 border-dashed rounded-3xl cursor-pointer transition-all ${selectedImage ? 'border-emerald-500 bg-emerald-50/20' : 'border-gray-100 bg-gray-50 hover:border-emerald-200 hover:bg-emerald-50/10'}`}
          >
              {selectedImage ? (
                  <div className="flex flex-col items-center justify-center p-4">
                      <div className="w-32 h-32 rounded-2xl overflow-hidden border-2 border-emerald-500 mb-4 shadow-xl">
                        <img src={selectedImage} alt="预览" className="w-full h-full object-cover" />
                      </div>
                      <div className="flex items-center gap-2 text-emerald-700 font-black text-sm">
                        <FileCheck className="w-5 h-5" /> 图片已就绪
                      </div>
                      <p className="text-[10px] font-bold text-emerald-600 mt-1 opacity-60">点击区域重新上传</p>
                  </div>
              ) : (
                  <div className="flex flex-col items-center justify-center text-gray-400 p-8">
                      <div className="w-16 h-16 bg-white rounded-2xl shadow-sm flex items-center justify-center mb-4 border border-gray-100">
                        <UploadCloud className="w-8 h-8 text-emerald-500" />
                      </div>
                      <p className="text-sm font-black text-gray-700">将菜肴照片拖到此处</p>
                      <p className="text-[10px] font-bold mt-2 tracking-wide uppercase">支持 JPEG, PNG 格式，最大 10MB</p>
                  </div>
              )}
              <input id="file-upload" type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
          </label>

          <button
            onClick={handleSubmit}
            disabled={isLoading || !selectedImage}
            className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-emerald-700 transition-all disabled:opacity-50 flex justify-center items-center shadow-xl shadow-emerald-200 active:scale-95"
          >
            {isLoading ? <Loader2 className="animate-spin w-5 h-5 mr-3"/> : <Camera className="w-5 h-5 mr-3" />}
            {isLoading ? '深度图像识别分析中...' : '提交图像分析匹配'}
          </button>
        </div>
      )}
    </div>
  );
};

export default PreferenceForm;

import React, { useState } from 'react';
import { RiceProduct } from '../types';
import { MapPin, ChevronRight, Package, X, Scale, Image as ImageIcon, Sparkles, Heart, Droplets, ExternalLink, ChevronLeft } from 'lucide-react';

interface ResultsGridProps {
  products: RiceProduct[];
  analysisText: string;
  favorites?: string[];
  onToggleFavorite?: (id: string) => void;
  showAnalysis?: boolean;
  onProductHover?: (product: RiceProduct | null) => void;
}

interface ProductDetailModalProps {
  product: RiceProduct;
  onClose: () => void;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
  accentColor: string;
}

export const ProductDetailModal: React.FC<ProductDetailModalProps> = ({ product, onClose, isFavorite, onToggleFavorite, accentColor }) => {
  const images = product.images && product.images.length > 0 ? product.images : (product.packagingImage ? [product.packagingImage] : []);
  const [currentImgIdx, setCurrentImgIdx] = useState(0);

  const nextImg = () => setCurrentImgIdx((prev) => (prev + 1) % images.length);
  const prevImg = () => setCurrentImgIdx((prev) => (prev - 1 + images.length) % images.length);

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col relative animate-in zoom-in-95 duration-300">

        <div className="flex justify-between items-center px-6 py-4 border-b border-gray-100 bg-white/80 backdrop-blur-md sticky top-0 z-30">
           <div className="flex flex-col min-w-0 pr-4">
              <h2 className="text-xl font-bold text-gray-900 truncate leading-tight">{product.name}</h2>
           </div>
           <div className="flex items-center gap-2 flex-shrink-0">
              {onToggleFavorite && (
                <button 
                  onClick={(e) => { e.stopPropagation(); onToggleFavorite(product.id); }} 
                  className={`p-2.5 rounded-full transition-all ${isFavorite ? 'bg-red-50 text-red-500' : 'bg-gray-50 text-gray-300 hover:text-gray-400'}`}
                >
                  <Heart className={`w-5 h-5 ${isFavorite ? 'fill-current' : ''}`} />
                </button>
              )}
              <button 
                onClick={onClose} 
                className="p-2.5 text-gray-400 hover:text-gray-900 bg-gray-50 rounded-full transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
           </div>
        </div>

        <div className="overflow-y-auto flex-1 custom-scrollbar">
          <div className="flex flex-col lg:flex-row h-full">
            {/* 图像库 */}
            <div className="w-full lg:w-1/2 bg-gray-50 flex flex-col items-center justify-center p-6 min-h-[350px] relative group border-r border-gray-50">
               <div className={`absolute top-0 left-0 w-full h-1.5 ${accentColor}`}></div>

               <div className="relative w-full aspect-square flex items-center justify-center bg-white rounded-2xl overflow-hidden shadow-inner border border-gray-100">
                  {images.length > 0 ? (
                      <>
                        <img src={images[currentImgIdx]} alt={product.name} className="w-full h-full object-contain transition-all duration-500" />
                        {images.length > 1 && (
                            <>
                                <button onClick={prevImg} className="absolute left-2 top-1/2 -translate-y-1/2 p-2 bg-black/10 hover:bg-black/20 text-white rounded-full transition-all backdrop-blur-sm">
                                    <ChevronLeft className="w-6 h-6" />
                                </button>
                                <button onClick={nextImg} className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-black/10 hover:bg-black/20 text-white rounded-full transition-all backdrop-blur-sm">
                                    <ChevronRight className="w-6 h-6" />
                                </button>
                            </>
                        )}
                      </>
                  ) : (
                    <div className="flex flex-col items-center text-gray-200">
                        <ImageIcon className="w-16 h-16 mb-2" />
                        <span className="text-xs font-bold uppercase tracking-widest">暂无图像</span>
                    </div>
                  )}
               </div>

               {images.length > 1 && (
                   <div className="flex gap-2 mt-4 overflow-x-auto w-full py-2 custom-scrollbar">
                       {images.map((img, i) => (
                           <button 
                                key={i} 
                                onClick={() => setCurrentImgIdx(i)}
                                className={`flex-shrink-0 w-16 h-16 rounded-lg border-2 overflow-hidden transition-all ${i === currentImgIdx ? 'border-emerald-500' : 'border-transparent opacity-60 hover:opacity-100'}`}
                           >
                               <img src={img} alt="" className="w-full h-full object-cover" />
                           </button>
                       ))}
                   </div>
               )}
            </div>

            <div className="w-full lg:w-1/2 p-8 space-y-6 flex flex-col">
               <div className="flex items-center text-sm text-gray-500 gap-6">
                  <div className="flex items-center"><MapPin className="w-4 h-4 mr-1.5 text-emerald-500" /> {product.origin}</div>
                  <div className="flex items-center"><Scale className="w-4 h-4 mr-1.5 text-emerald-500" /> {product.weight}公斤</div>
                  <div className="ml-auto text-2xl font-black text-emerald-600">¥{product.price}<span className="text-xs font-normal text-gray-400">/公斤</span></div>
               </div>

               <div className="bg-blue-50/50 p-4 rounded-2xl border border-blue-100 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                     <div className="p-2.5 bg-blue-500 rounded-xl text-white shadow-lg shadow-blue-100">
                        <Droplets className="w-5 h-5" />
                     </div>
                     <div>
                        <h4 className="text-[10px] font-black text-blue-600 uppercase tracking-widest">最佳推荐米水比</h4>
                        <div className="text-xl font-black text-blue-900 leading-none mt-1">{product.cookingRatio}</div>
                     </div>
                  </div>
                  <div className="text-[10px] text-blue-400 font-bold text-right leading-tight max-w-[100px]">
                     建议搭配软质纯净水
                  </div>
               </div>

               <div className="bg-emerald-50/80 p-5 rounded-2xl border border-emerald-100/50">
                  <h4 className="text-xs font-black text-emerald-800 uppercase tracking-widest mb-2 flex items-center gap-2">
                    <Sparkles className="w-3.5 h-3.5 text-amber-500" /> 智能融合匹配分析
