import React, { useState } from 'react';
import { X, UserPlus, LogIn, AlertCircle, Loader2 } from 'lucide-react';

interface UserAuthModalProps {
  initialMode?: 'login' | 'register';
  initialRole: 'User' | 'Merchant' | 'Admin';
  onClose: () => void;
  onLogin: (username: string, password?: string) => Promise<void>;
  onRegister: (username: string, password?: string, role?: 'User' | 'Merchant' | 'Admin') => Promise<void>;
}

const UserAuthModal: React.FC<UserAuthModalProps> = ({ initialMode = 'login', initialRole, onClose, onLogin, onRegister }) => {
  const [mode, setMode] = useState<'login' | 'register'>(initialMode);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const themeStyles = {
    Admin: { color: 'amber', label: '系统管理总台', btn: 'bg-amber-500 hover:bg-amber-600 shadow-amber-200', bg: 'bg-amber-50' },
    Merchant: { color: 'blue', label: '商家管理中心', btn: 'bg-blue-600 hover:bg-blue-700 shadow-blue-200', bg: 'bg-blue-50' },
    User: { color: 'emerald', label: '用户门户', btn: 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200', bg: 'bg-emerald-50' }
  };

  const theme = themeStyles[initialRole];

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) {
      setError("请输入完整的账号和密码");
      return;
    }

    setError('');
    setIsSubmitting(true);
    try {
      if (mode === 'login') {
        await onLogin(username, password);
      } else {
        await onRegister(username, password, initialRole);
      }
      onClose();
    } catch (err: any) {
      setError(err.message || "登录过程中发生错误，请重试。");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[300] flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
        <div className={`px-6 py-5 border-b border-gray-100 flex justify-between items-center ${theme.bg}`}>
          <div className="flex flex-col">
            <h3 className="font-bold text-gray-900 leading-tight">
              {mode === 'login' ? '账户登录' : '新账户注册'}
            </h3>
            <span className={`text-[10px] font-black uppercase tracking-widest mt-0.5 text-${theme.color}-600`}>
                {theme.label}
            </span>
          </div>
          <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 transition-colors bg-white/50 rounded-full">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">用户名</label>
            <input
              type="text"
              required
              disabled={isSubmitting}
              value={username}
              onChange={(e) => { setUsername(e.target.value); setError(''); }}
              className="w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm focus:ring-2 focus:ring-gray-200 disabled:opacity-50"
              placeholder="请输入您的账号"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">密码</label>
            <input
              type="password"
              required
              disabled={isSubmitting}
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className="w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm focus:ring-2 focus:ring-gray-200 disabled:opacity-50"
              placeholder="请输入您的密码"
            />
          </div>

          {error && (
            <div className="flex items-center gap-2 text-xs text-red-600 bg-red-50 p-3.5 rounded-xl border border-red-100 animate-in shake duration-300">
              <AlertCircle className="w-4 h-4 flex-shrink-0" />
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className={`w-full text-white py-4 rounded-2xl font-bold transition-all flex justify-center items-center gap-2 shadow-xl active:scale-95 disabled:opacity-70 ${theme.btn}`}
          >
            {isSubmitting ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : mode === 'login' ? (
              <>
                <LogIn className="w-4 h-4" /> 确认登录
              </>
            ) : (
              <>
                <UserPlus className="w-4 h-4" /> 立即注册
              </>
            )}
          </button>

          {initialRole !== 'Admin' && (
              <div className="text-center pt-2">
                <button
                  type="button"
                  disabled={isSubmitting}
                  onClick={() => {
                    setMode(mode === 'login' ? 'register' : 'login');
                    setError('');
                  }}
                  className={`text-xs font-bold transition-colors text-${theme.color}-600 hover:text-${theme.color}-700`}
                >
                  {mode === 'login' ? '还没有账号？前往注册' : '已有账号？前往登录'}
                </button>
              </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default UserAuthModal;

import { RiceProduct, UserProfile } from '../types.ts';

const DB_KEYS = {
  INVENTORY: 'rice_db_inventory',
  USERS: 'rice_db_users'
};

const RICE_IMAGE_POOL = [
  "https://images.unsplash.com/photo-1586201375761-83865001e31c?auto=format&fit=crop&q=80&w=800",
  "https://images.unsplash.com/photo-1590483734724-38fa19dd7b3c?auto=format&fit=crop&q=80&w=800",
  "https://images.unsplash.com/photo-1536304993881-ff6e9eefa2a6?auto=format&fit=crop&q=80&w=800",
  "https://images.unsplash.com/photo-1626071494507-dc79630ccb9c?auto=format&fit=crop&q=80&w=800",
  "https://images.unsplash.com/photo-1501166243542-a7f457193963?auto=format&fit=crop&q=80&w=800",
];

const PROVINCES = ['黑龙江', '吉林', '辽宁', '江苏', '浙江', '安徽', '湖北', '湖南', '江西', '广东', '广西', '泰国', '日本', '越南'];
const RICE_VARIANTS = ['稻花香', '长粒香', '丝苗米', '越光米', '蟹田米', '珍珠米', '小农占', '茉莉香米', '秋田小町', '玄米', '胚芽米'];
const BRANDS = ['金龙鱼', '福临门', '北大荒', '十月稻田', '柴火大院', '华润五丰', '恒大兴安', '燕之坊'];

const generateInitialData = (): RiceProduct[] => {
  const data: RiceProduct[] = [];
  for (let i = 1; i <= 100; i++) {
    const id = `R${i.toString().padStart(3, '0')}`;
    const province = PROVINCES[Math.floor(Math.random() * PROVINCES.length)];
    const variant = RICE_VARIANTS[Math.floor(Math.random() * RICE_VARIANTS.length)];
    const brand = BRANDS[Math.floor(Math.random() * BRANDS.length)];
    const price = Number((Math.random() * 45 + 5).toFixed(1));
    const weight = [1, 2.5, 5, 10][Math.floor(Math.random() * 4)];
    const textureScore = Math.floor(Math.random() * 70 + 30);
    const aromaScore = Math.floor(Math.random() * 70 + 30);
    const stock = Math.floor(Math.random() * 2000);

    const ownerId = i <= 50 ? 'M001' : `M${Math.floor(Math.random() * 5 + 2).toString().padStart(3, '0')}`;

    let cookingRatio = "1:1.2";
    if (variant === '玄米' || variant === '胚芽米') {
      cookingRatio = "1:1.8";
    } else if (variant === '丝苗米' || variant === '长粒香') {
      cookingRatio = "1:1.4";
    } else if (textureScore > 80) {
      cookingRatio = "1:1.1";
    }

    let status: 'Normal' | 'Low Stock' | 'Critical' = 'Normal';
    if (stock < 100) status = 'Critical';
    else if (stock < 500) status = 'Low Stock';

    const mainImg = RICE_IMAGE_POOL[i % RICE_IMAGE_POOL.length];

    data.push({
      id,
      ownerId,
      name: `${brand}${province}${variant}`,
      origin: `${province}核心产区`,
      price,
      weight,
      textureScore,
      aromaScore,
      cookingRatio,
      packagingImage: mainImg,
      images: [mainImg, RICE_IMAGE_POOL[(i + 1) % RICE_IMAGE_POOL.length]],
      purchaseUrl: `https://item.jd.com/${Math.floor(Math.random() * 10000000)}.html`,
      description: `精选来自${province}的${variant}，采用物理去壳工艺。口感${textureScore > 70 ? '软糯' : '清爽'}，最佳建议烹饪比例为米水比 ${cookingRatio}。`,
      tags: [variant, province, price > 30 ? '高端礼赠' : '大众消费', '新米上市'],
      stock,
      status,
      matchReason: ''
    });
  }
  return data;
};

const INITIAL_USERS: UserProfile[] = [
  { id: 'A001', username: 'admin', password: 'admin', ip: '127.0.0.1', role: 'Admin', status: 'Active', lastActive: '刚刚', requestCount: 0, favorites: [] },
  { id: 'M001', username: 'merchant', password: 'merchant', ip: '127.0.0.1', role: 'Merchant', status: 'Active', lastActive: '刚刚', requestCount: 0, favorites: [] }
];

const delay = (ms: number = 600) => new Promise(res => setTimeout(res, ms));

export const MockBackend = {
  getInventory: async (): Promise<RiceProduct[]> => {
    await delay();
    const data = localStorage.getItem(DB_KEYS.INVENTORY);
    if (!data) {
      const initial = generateInitialData();
      localStorage.setItem(DB_KEYS.INVENTORY, JSON.stringify(initial));
      return initial;
    }
    return JSON.parse(data);
  },

  getUsers: async (): Promise<UserProfile[]> => {
    await delay();
    const data = localStorage.getItem(DB_KEYS.USERS);
    let users: UserProfile[] = data ? JSON.parse(data) : [...INITIAL_USERS];

    INITIAL_USERS.forEach(initialUser => {
      if (!users.some(u => u.username === initialUser.username)) {
        users.push(initialUser);
      }
    });

    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
    return users;
  },

  saveProduct: async (product: RiceProduct): Promise<RiceProduct> => {
    await delay(800);
    const data = await MockBackend.getInventory();
    const index = data.findIndex(p => p.id === product.id);
    if (index > -1) {
      data[index] = product;
    } else {
      data.push(product);
    }
    localStorage.setItem(DB_KEYS.INVENTORY, JSON.stringify(data));
    return product;
  },

  updateUser: async (user: UserProfile): Promise<UserProfile> => {
    await delay(500);
    const users = await MockBackend.getUsers();
    const updated = users.map(u => u.id === user.id ? user : u);
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(updated));
    return user;
  },

  register: async (user: UserProfile): Promise<UserProfile> => {
    await delay(1000);
    const users = await MockBackend.getUsers();
    if (users.some(u => u.username === user.username)) throw new Error("用户名已存在");
    users.push(user);
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
    return user;
  }
};

