import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceProduct } from "../../types.ts";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const recommendationSchema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "推荐理由" }
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: { type: Type.STRING, description: "综合分析报告，仅说明筛选理由和口感建议" },
  },
  required: ["recommendations", "analysis"],
};

export const handleTextRecommendationRequest = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const ai = getAIClient();

  // 关键修复：在库存字符串中包含价格，使 AI 能够识别预算约束
  const inventoryStr = inventory.map(p => `编号:${p.id}|名称:${p.name}|产地:${p.origin}|价格:${p.price}元/kg`).join('\n');

  const prompt = `
    作为稻米专家，请从以下库中匹配最适合的产品。

    用户偏好与约束：
    - 预算范围：${prefs.minPrice || 0} 到 ${prefs.maxPrice || '不限'} 元/kg (这是硬性约束，推荐的产品价格必须在此范围内)
    - 产地要求：${prefs.origin || '不限'}
    - 口感偏好：${prefs.texture || '不限'}
    - 米粒形态：${prefs.grainLength || '不限'}
    - 是否要求香气：${prefs.aroma ? '是' : '否'}
    - 其他补充需求：${prefs.requirements || '无'}

    现有库数据：
    ${inventoryStr}

    要求：
    1. 严格遵守预算范围限制。不要推荐超出用户预算上限的产品。
    2. 基于产品的口感、产地和价格进行最优匹配。
    3. 在 analysis 字段提供一段综合分析报告，直接说明筛选逻辑。并在报告结尾提示用户：“您可点击对应产品的‘立即购买’或进入详情页获取选购链接”。
    4. 严禁提及任何关于“AI分析”、“算法匹配”等技术术语，仅保留专业的稻米选购建议。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: recommendationSchema,
    },
  });

  const parsed = JSON.parse(response.text || "{}");

  const recommendations = (parsed.recommendations || [])
    .map((rec: any) => {
      const product = inventory.find(p => p.id === rec.id);
      return product ? { ...product, matchReason: rec.matchReason } : null;
    })
    .filter((item: any) => item !== null);

  return { 
    recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
    analysis: parsed.analysis || "根据您的偏好，我们为您挑选了口感与产地最为契合的稻米品种。您可以点击下方产品的‘立即购买’按钮直达选购。" 
  };
};

export const handleImageAnalysisRequest = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const ai = getAIClient();
  const inventoryStr = inventory.map(p => `编号:${p.id}|名称:${p.name}|价格:${p.price}元/kg`).join('\n');

  const promptText = `
          分析图中菜肴的口味特征（如：咸鲜、甜辣、软烂等），并从以下稻米库中推荐最适合搭配的米种：
          ${inventoryStr}

          要求：
          1. 说明菜肴风味与稻米特性的搭配逻辑。
          2. analysis 字段应聚焦于饮食文化和口感平衡。并温馨提示用户可以通过点击‘立即购买’按钮快速下单。
          3. 推荐时尽量考虑性价比，除非菜肴看起来非常高端。
          4. 语气应自然、生活化，严禁提及“图像识别”等背景逻辑。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: promptText }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: recommendationSchema,
    }
  });

  const parsed = JSON.parse(response.text || "{}");

  const recommendations = (parsed.recommendations || [])
    .map((rec: any) => {
      const product = inventory.find(p => p.id === rec.id);
      return product ? { ...product, matchReason: rec.matchReason } : null;
    })
    .filter((item: any) => item !== null);

  return { 
    recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
    analysis: parsed.analysis || "这款菜肴的味道浓郁，搭配我们为您选出的米种能带来更好的味觉平衡。请点击‘立即购买’按钮获取产品链接。" 
  };
};

import { RiceProduct, UserProfile } from '../types.ts';

const DB_KEYS = {
  INVENTORY: 'rice_db_inventory',
  USERS: 'rice_db_users'
};

const RICE_IMAGE_POOL = [
  "https://images.unsplash.com/photo-1586201375761-83865001e31c?auto=format&fit=crop&q=80&w=800",
  "https://images.unsplash.com/photo-1590483734724-38fa19dd7b3c?auto=format&fit=crop&q=80&w=800",
