};

export default App;

import React, { useState } from 'react';
import { Database, Users, LogOut, Plus, X, Save, Pencil, Search, ShieldAlert, CheckCircle, Ban, UserPlus, Image as ImageIcon, Store, Activity, Droplets, ShieldCheck, UserCircle, HelpCircle, Trash2, Upload, MapPinned } from 'lucide-react';
import { RiceProduct, UserProfile } from '../types.ts';

interface AdminDashboardProps {
  onLogout: () => void;
  inventory: RiceProduct[];
  onAddProduct: (product: RiceProduct) => void;
  onUpdateProduct: (product: RiceProduct) => void;
  users: UserProfile[];
  onUpdateUsers: (users: UserProfile[]) => void;
  currentUser: UserProfile | null;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, inventory, onAddProduct, onUpdateProduct, users, onUpdateUsers, currentUser }) => {
  const [activeTab, setActiveTab] = useState<'data' | 'users'>('data');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [productSearch, setProductSearch] = useState('');

  const [userSearch, setUserSearch] = useState('');
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [userForm, setUserForm] = useState<Partial<UserProfile>>({
    username: '',
    role: 'User',
    status: 'Active',
    shopAddress: ''
  });

  const isAdmin = currentUser?.role === 'Admin';

  const myInventory = isAdmin 
    ? inventory 
    : inventory.filter(p => p.ownerId === currentUser?.id);

  const [newProduct, setNewProduct] = useState<Partial<RiceProduct>>({
    name: '',
    origin: '',
    price: 0,
    weight: 5,
    textureScore: 50,
    aromaScore: 50,
    cookingRatio: '1:1.2',
    stock: 100,
    status: 'Normal',
    description: '',
    purchaseUrl: '',
    shopAddress: currentUser?.shopAddress || '',
    images: []
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNewProduct(prev => ({ 
        ...prev, 
        [name]: ['price', 'stock', 'textureScore', 'aromaScore', 'weight'].includes(name)
            ? Math.max(0, Number(value))
            : value 
    }));
  };

  const handleMultipleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const fileArray = Array.from(files) as File[];
      fileArray.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setNewProduct(prev => ({
            ...prev,
            images: [...(prev.images || []), reader.result as string]
          }));
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setNewProduct(prev => ({
      ...prev,
      images: (prev.images || []).filter((_, i) => i !== index)
    }));
  };

  const openAddModal = () => {
    setEditingId(null);
    setNewProduct({ name: '', origin: '', price: 0, weight: 5, textureScore: 50, aromaScore: 50, cookingRatio: '1:1.2', stock: 100, status: 'Normal', description: '', purchaseUrl: '', shopAddress: currentUser?.shopAddress || '', images: [] });
    setShowAddModal(true);
  };

  const openEditModal = (product: RiceProduct) => {
    setEditingId(product.id);
    setNewProduct({ ...product, images: product.images || (product.packagingImage ? [product.packagingImage] : []) });
    setShowAddModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || !newProduct.origin) return;

    const finalImages = newProduct.images || [];
    const mainImg = finalImages.length > 0 ? finalImages[0] : '';

    if (editingId) {
        const originalProduct = inventory.find(p => p.id === editingId);
        const updatedProduct: RiceProduct = {
            ...newProduct as RiceProduct,
            id: editingId,
            ownerId: originalProduct?.ownerId || currentUser?.id,
            packagingImage: mainImg,
            images: finalImages,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
        };
        onUpdateProduct(updatedProduct);
    } else {
        const productToAdd: RiceProduct = {
            id: `R${Math.floor(Math.random() * 10000).toString().padStart(3, '0')}`,
            ownerId: currentUser?.id,
            name: newProduct.name!,
            origin: newProduct.origin!,
            price: newProduct.price || 0,
            weight: newProduct.weight || 5,
            textureScore: newProduct.textureScore || 50,
            aromaScore: newProduct.aromaScore || 50,
            cookingRatio: newProduct.cookingRatio || '1:1.2',
            stock: newProduct.stock || 0,
            packagingImage: mainImg,
            images: finalImages,
            purchaseUrl: newProduct.purchaseUrl || '',
            shopAddress: newProduct.shopAddress || currentUser?.shopAddress || '',
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
            description: newProduct.description || '暂无描述',
            matchReason: '',
            tags: []
        };
        onAddProduct(productToAdd);
    }

    setShowAddModal(false);
  };

  const handleUserInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setUserForm(prev => ({ ...prev, [name]: value }));
  };

  const openAddUserModal = () => {
    setEditingUserId(null);
    setUserForm({ username: '', role: 'User', status: 'Active', shopAddress: '' });
    setShowUserModal(true);
  };

  const openEditUserModal = (user: UserProfile) => {
    setEditingUserId(user.id);
    setUserForm({ username: user.username, role: user.role, status: user.status, shopAddress: user.shopAddress || '' });
    setShowUserModal(true);
  };

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userForm.username) return;

    if (editingUserId) {
        onUpdateUsers(users.map(u => u.id === editingUserId ? { ...u, ...userForm } as UserProfile : u));
    } else {
        const newUser: UserProfile = {
            id: `U${Math.floor(Math.random() * 10000)}`,
            username: userForm.username!,
            role: userForm.role as 'User' | 'Merchant' | 'Admin',
            status: userForm.status as 'Active' | 'Banned',
            ip: `192.168.1.${Math.floor(Math.random() * 255)}`,
            lastActive: '刚刚',
            requestCount: 0,
            favorites: [],
            shopAddress: userForm.shopAddress
        };
        onUpdateUsers([newUser, ...users]);
    }
    setShowUserModal(false);
  };

  const toggleUserStatus = (userId: string) => {
      onUpdateUsers(users.map(user => {
          if (user.id === userId) {
              return { ...user, status: user.status === 'Active' ? 'Banned' : 'Active' };
          }
          return user;
      }));
  };

  const filteredUsers = users.filter(u => 
    u.username.toLowerCase().includes(userSearch.toLowerCase()) || 
    u.id.toLowerCase().includes(userSearch.toLowerCase())
  );

  const filteredInventory = myInventory.filter(item => 
    item.name.toLowerCase().includes(productSearch.toLowerCase()) || 
    item.origin.toLowerCase().includes(productSearch.toLowerCase()) ||
    item.id.toLowerCase().includes(productSearch.toLowerCase())
  );

  const getStatusLabel = (status?: string) => {
    switch(status) {
      case 'Critical': return '极低';
      case 'Low Stock': return '低库存';
      default: return '充足';
    }
  };

  const getMerchantName = (ownerId?: string) => {
    if (!ownerId) return '系统直营';
    const merchant = users.find(u => u.id === ownerId);
    return merchant ? merchant.username : '未知商家';
  };

  const themeColorClass = isAdmin ? 'amber' : 'blue';

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col relative">
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex justify-between items-center sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${isAdmin ? 'bg-amber-500' : 'bg-blue-600'}`}>
            {isAdmin ? <ShieldCheck className="text-white w-5 h-5" /> : <Store className="text-white w-5 h-5" />}
          </div>
          <div>
            <h1 className="font-bold text-gray-900 text-lg">稻米系统 <span className={`text-xs font-normal text-white px-2 py-0.5 rounded-full ml-1 ${isAdmin ? 'bg-amber-500' : 'bg-blue-600'}`}>{isAdmin ? '系统总控' : '商家中心'}</span></h1>
            <p className="text-[10px] text-gray-400">{isAdmin ? '全局权限与用户管理中心' : '商品发布与库存管理系统'}</p>
          </div>
        </div>
        <button onClick={onLogout} className="text-sm text-gray-500 hover:text-red-600 flex items-center gap-2 transition-colors">
          <LogOut className="w-4 h-4" />
          退出管理系统
        </button>
      </header>

      <div className="flex flex-1 overflow-hidden">
        <aside className="w-64 bg-white border-r border-gray-200 flex-shrink-0 hidden md:block">
          <nav className="p-4 space-y-1">
            <button
              onClick={() => setActiveTab('data')}
              className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'data' ? (isAdmin ? 'bg-amber-50 text-amber-700' : 'bg-blue-50 text-blue-700') : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Database className="w-4 h-4" />
              {isAdmin ? '全局库存概览' : '我的库存管理'}
            </button>
            {isAdmin && (
              <button
                onClick={() => setActiveTab('users')}
                className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'users' ? 'bg-amber-50 text-amber-700' : 'text-gray-600 hover:bg-gray-50'}`}
              >
                <Users className="w-4 h-4" />
                全平台用户管理
              </button>
            )}
          </nav>
        </aside>

        <main className="flex-1 overflow-y-auto p-6 md:p-8">
          {activeTab === 'data' && (
            <div className="space-y-6 animate-in fade-in duration-300">
               <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                 <div>
                    <h2 className="text-xl font-bold text-gray-900 mb-1">{isAdmin ? '全量库存数据库' : '我的稻米库'}</h2>
                    <p className="text-sm text-gray-500">管理{isAdmin ? '全平台' : '您的'}上架商品，当前显示 {filteredInventory.length} / 总计 {myInventory.length} 条</p>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                        <input
                            type="text"
                            placeholder="快速检索商品..."
                            value={productSearch}
                            onChange={(e) => setProductSearch(e.target.value)}
                            className={`w-full bg-white border border-gray-200 rounded-lg pl-10 pr-4 py-2 text-sm focus:ring-2 ${isAdmin ? 'focus:ring-amber-500 focus:border-amber-500' : 'focus:ring-blue-500 focus:border-blue-500'}`}
                        />
                    </div>
                    <button 
                        onClick={openAddModal}
                        className={`${isAdmin ? 'bg-amber-500 hover:bg-amber-600' : 'bg-blue-600 hover:bg-blue-700'} text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2 whitespace-nowrap`}
                    >
                        <Plus className="w-4 h-4" />
                        发布新稻米
                    </button>
                 </div>
               </div>

               <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
                  <table className="w-full text-sm text-left">
                    <thead className="bg-gray-50 text-gray-500 font-medium">
                      <tr>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">SKU</th>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">展示图</th>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">商品名称</th>
                        {isAdmin && <th className="px-6 py-4 text-[11px] uppercase tracking-wider">商家来源</th>}
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">单价/水比</th>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">库存状态</th>
                        <th className="px-6 py-4 text-right">操作</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {filteredInventory.map(rice => (
                          <tr key={rice.id} className="hover:bg-gray-50 transition-colors">
                          <td className="px-6 py-4 font-mono text-[10px] text-gray-400">{rice.id}</td>
                          <td className="px-6 py-4">
                              {(rice.images && rice.images.length > 0) || rice.packagingImage ? (
                                <img src={rice.images?.[0] || rice.packagingImage} alt="外观" className="w-10 h-10 object-cover rounded-md border border-gray-100 shadow-sm" />
                              ) : (
                                <div className="w-10 h-10 bg-gray-100 rounded-md flex items-center justify-center text-gray-300">
                                    <ImageIcon className="w-4 h-4" />
                                </div>
                              )}
                          </td>
                          <td className="px-6 py-4 font-medium text-gray-900">
                              <div className="text-sm">{rice.name}</div>
                              <div className="text-[10px] text-gray-400 truncate max-w-[150px]">{rice.shopAddress || rice.origin}</div>
                          </td>
                          {isAdmin && (
                            <td className="px-6 py-4">
                               <div className="flex items-center gap-2">
                                  <UserCircle className="w-3.5 h-3.5 text-amber-500" />
                                  <span className="text-xs font-semibold text-gray-600">{getMerchantName(rice.ownerId)}</span>
                               </div>
                            </td>
                          )}
                          <td className="px-6 py-4 text-gray-600">
                              <div className={`font-bold text-sm ${isAdmin ? 'text-amber-600' : 'text-blue-600'}`}>{rice.cookingRatio}</div>
                              <div className="text-[10px] text-gray-400">{rice.weight}kg/¥{rice.price}</div>
                          </td>
                          <td className="px-6 py-4">
                              <span className={`inline-flex items-center px-2 py-1 rounded-full text-[10px] font-bold ${
                                rice.status === 'Critical' ? 'bg-red-50 text-red-700' :
                                rice.status === 'Low Stock' ? 'bg-amber-50 text-amber-700' :
                                'bg-green-50 text-green-700'
                              }`}>
                                {rice.stock} ({getStatusLabel(rice.status)})
                              </span>
                          </td>
                          <td className="px-6 py-4 text-right">
                              <button 
                                  onClick={() => openEditModal(rice)}
                                  className={`text-gray-400 hover:text-${isAdmin ? 'amber' : 'blue'}-600 transition-colors p-1`}
                              >
                                  <Pencil className="w-4 h-4" />
                              </button>
                          </td>
                          </tr>
                      ))}
                    </tbody>
                  </table>
                  {filteredInventory.length === 0 && (
                    <div className="py-20 text-center text-gray-400">
                        <Database className="w-12 h-12 mx-auto mb-3 opacity-20" />
                        <p className="text-sm font-medium">暂无相关稻米数据</p>
                    </div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'users' && isAdmin && (
