               </div>

               <div className="space-y-3">
                  <h4 className="text-xs font-black text-gray-900 uppercase tracking-widest">产品风味描述</h4>
                  <p className="text-sm text-gray-500 leading-relaxed border-l-4 border-emerald-100 pl-4">
                    {product.description}
                  </p>
               </div>

               <div className="flex-1 min-h-[40px]"></div>

               {/* 购买途径展示区 - 展示实际店铺地址 */}
               <div className="pt-6 border-t border-gray-100 flex flex-col gap-4">
                  <div className="bg-gray-50 p-5 rounded-2xl border border-gray-100 space-y-4">
                      <div className="flex items-start gap-4">
                        <div className="p-2.5 bg-emerald-100 rounded-xl text-emerald-600">
                          <Store className="w-5 h-5" />
                        </div>
                        <div className="flex-1">
                          <h4 className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">店铺实际地址 (首选)</h4>
                          <p className="text-sm text-gray-800 font-black">
                            {product.shopAddress || "产地工厂直发，请联系当地经销商"}
                          </p>
                        </div>
                      </div>

                      {product.purchaseUrl && (
                        <div className="flex items-start gap-4 pt-2 border-t border-gray-200/50">
                          <div className="p-2.5 bg-blue-50 rounded-xl text-blue-500">
                            <ShoppingBag className="w-5 h-5" />
                          </div>
                          <div className="flex-1">
                            <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1">线上辅助途径</h4>
                            <p className="text-sm text-gray-800 font-bold">
                              {product.purchaseUrl}
                            </p>
                          </div>
                        </div>
                      )}

                      <p className="text-[10px] text-gray-400 font-medium leading-relaxed italic text-center">
                        * 毕业设计演示作品：本系统仅提供推荐信息，请前往上述地址或通过文字指引搜索该产品。
                      </p>
                  </div>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

